import { useState, useEffect } from 'preact/hooks';

export function useApi<T>(url: string, deps: unknown[] = []) {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);

    fetch(url)
      .then(async (res) => {
        if (res.status === 401) {
          window.location.hash = '#/login';
          return;
        }
        if (!res.ok) {
          const body = (await res.json().catch(() => ({}))) as { error?: string };
          throw new Error(body.error ?? `HTTP ${res.status}`);
        }
        return res.json() as Promise<T>;
      })
      .then((d) => {
        if (!cancelled && d !== undefined) {
          setData(d);
          setLoading(false);
        }
      })
      .catch((err: Error) => {
        if (!cancelled) {
          setError(err.message);
          setLoading(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [url, ...deps]);

  return { data, loading, error };
}

export async function apiPost<T>(
  url: string,
  body: unknown,
): Promise<{ data?: T; error?: string }> {
  try {
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = (await res.json().catch(() => ({}))) as T;
    if (!res.ok) return { error: (data as { error?: string }).error ?? `HTTP ${res.status}` };
    return { data };
  } catch (e) {
    return { error: (e as Error).message };
  }
}

export async function apiPatch<T>(
  url: string,
  body: unknown,
): Promise<{ data?: T; error?: string }> {
  try {
    const res = await fetch(url, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = (await res.json().catch(() => ({}))) as T;
    if (!res.ok) return { error: (data as { error?: string }).error ?? `HTTP ${res.status}` };
    return { data };
  } catch (e) {
    return { error: (e as Error).message };
  }
}

import { render } from 'preact';
import { useState, useEffect } from 'preact/hooks';
import { Login } from './pages/Login.js';
import { Dashboard } from './pages/Dashboard.js';
import { MatchCreator } from './pages/MatchCreator.js';
import { MatchDetail } from './pages/MatchDetail.js';
import { UserList } from './pages/UserList.js';
import { UserDetail } from './pages/UserDetail.js';
import { Reports } from './pages/Reports.js';

function parseHash(hash: string): { route: string; params: Record<string, string> } {
  const path = hash.replace(/^#\/?/, '') || '/';
  const parts = path.split('/');

  if (parts[0] === 'matches' && parts[1] === 'new') return { route: 'match-creator', params: {} };
  if (parts[0] === 'matches' && parts[1])
    return { route: 'match-detail', params: { matchId: parts[1] } };
  if (parts[0] === 'users' && parts[1])
    return { route: 'user-detail', params: { userId: parts[1] } };
  if (parts[0] === 'users') return { route: 'user-list', params: {} };
  if (parts[0] === 'reports') return { route: 'reports', params: {} };
  if (parts[0] === 'login') return { route: 'login', params: {} };
  return { route: 'dashboard', params: {} };
}

function Sidebar({ route }: { route: string }) {
  const navLink = (href: string, label: string, active: boolean) => (
    <a href={href} class={`app-nav-link${active ? ' active' : ''}`}>
      {label}
    </a>
  );

  return (
    <nav class="app-nav">
      <div class="app-nav-brand">
        Phalanx
        <br />
        Admin
      </div>

      <div class="app-nav-section">
        <div class="app-nav-label">Overview</div>
        {navLink('#/', 'Dashboard', route === 'dashboard')}
      </div>

      <div class="app-nav-section">
        <div class="app-nav-label">Matches</div>
        {navLink('#/matches/new', 'New Match', route === 'match-creator')}
      </div>

      <div class="app-nav-section">
        <div class="app-nav-label">Players</div>
        {navLink('#/users', 'All Users', route === 'user-list' || route === 'user-detail')}
      </div>

      <div class="app-nav-section">
        <div class="app-nav-label">Analytics</div>
        {navLink('#/reports', 'Queries', route === 'reports')}
      </div>
    </nav>
  );
}

function App() {
  const [hash, setHash] = useState(window.location.hash);

  useEffect(() => {
    const handler = () => {
      setHash(window.location.hash);
    };
    window.addEventListener('hashchange', handler);
    return () => {
      window.removeEventListener('hashchange', handler);
    };
  }, []);

  const { route, params } = parseHash(hash);

  if (route === 'login') return <Login />;

  return (
    <div class="app-shell">
      <Sidebar route={route} />
      <main class="app-content">
        {route === 'dashboard' && <Dashboard />}
        {route === 'match-creator' && <MatchCreator />}
        {route === 'match-detail' && <MatchDetail matchId={params.matchId!} />}
        {route === 'user-list' && <UserList />}
        {route === 'user-detail' && <UserDetail userId={params.userId!} />}
        {route === 'reports' && <Reports />}
      </main>
    </div>
  );
}

render(<App />, document.getElementById('app')!);

import { useEffect, useState } from 'preact/hooks';
import { useApi } from '../hooks/useApi.js';
import { StatBadge } from '../components/StatBadge.js';
import { DataTable } from '../components/DataTable.js';
import { IntegrityBadge } from '../components/IntegrityBadge.js';

interface MatchRow {
  id: string;
  player_1_name: string;
  player_2_name: string;
  bot_strategy: string | null;
  status: string;
  outcome: { victoryType?: string; winnerName?: string } | null;
  created_at: string;
  total_turns: number;
  verified_turns: number;
}

interface UserRow {
  id: string;
}

function timeAgo(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
  if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
  if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
  return `${Math.floor(diff / 86400000)}d ago`;
}

export function Dashboard() {
  const { data: activeMatches } = useApi<MatchRow[]>('/admin-api/matches?status=active');
  const { data: recentMatches } = useApi<MatchRow[]>(
    '/admin-api/matches?status=completed&limit=20',
  );
  const { data: users } = useApi<UserRow[]>('/admin-api/users?limit=1');
  const [, setTick] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setTick((t) => t + 1);
    }, 30000);
    return () => {
      clearInterval(interval);
    };
  }, []);

  const today = new Date().toDateString();
  const todayCount = (recentMatches ?? []).filter(
    (m) => new Date(m.created_at).toDateString() === today,
  ).length;
  const botPct =
    recentMatches && recentMatches.length > 0
      ? Math.round(
          ((recentMatches ?? []).filter((m) => m.bot_strategy).length / recentMatches.length) * 100,
        )
      : 0;

  return (
    <div class="page">
      <h1 class="page-title">Dashboard</h1>
      <p class="page-subtitle">Live operations overview — refreshes every 30s</p>

      <div class="stat-grid">
        <StatBadge
          label="Active Matches"
          value={(activeMatches ?? []).length}
          color="var(--green)"
        />
        <StatBadge label="Today's Matches" value={todayCount} />
        <StatBadge label="Total Users" value={users?.length ?? '...'} />
        <StatBadge label="Bot Match %" value={`${botPct}%`} color="var(--blue)" />
      </div>

      <div class="card" style={{ marginBottom: '16px' }}>
        <div class="card-title">Live Matches ({(activeMatches ?? []).length})</div>
        <DataTable<MatchRow>
          columns={[
            {
              key: 'id',
              label: 'Match ID',
              render: (r) => (
                <a href={`#/matches/${r.id}`} class="mono">
                  {r.id.slice(0, 8)}...
                </a>
              ),
            },
            {
              key: 'players',
              label: 'Players',
              render: (r) => `${r.player_1_name} vs ${r.player_2_name}`,
            },
            { key: 'bot', label: 'Bot', render: (r) => r.bot_strategy ?? '—' },
            { key: 'created_at', label: 'Started', render: (r) => timeAgo(r.created_at) },
          ]}
          rows={activeMatches ?? []}
          keyFn={(r) => r.id}
        />
      </div>

      <div class="card">
        <div class="card-title">Recent Matches</div>
        <DataTable<MatchRow>
          columns={[
            {
              key: 'id',
              label: 'Match ID',
              render: (r) => (
                <a href={`#/matches/${r.id}`} class="mono">
                  {r.id.slice(0, 8)}...
                </a>
              ),
            },
            { key: 'winner', label: 'Winner', render: (r) => r.outcome?.winnerName ?? '—' },
            { key: 'victory', label: 'Victory', render: (r) => r.outcome?.victoryType ?? '—' },
            { key: 'turns', label: 'Turns', render: (r) => String(r.total_turns) },
            {
              key: 'integrity',
              label: 'Check',
              render: (r) => <IntegrityBadge ok={r.verified_turns === r.total_turns} />,
            },
            { key: 'created_at', label: 'Ended', render: (r) => timeAgo(r.created_at) },
          ]}
          rows={recentMatches ?? []}
          keyFn={(r) => r.id}
        />
      </div>
    </div>
  );
}

import { useState } from 'preact/hooks';
import { apiPost } from '../hooks/useApi.js';

export function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: Event) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    const { error: err } = await apiPost('/admin-api/auth/login', { email, password });
    setLoading(false);
    if (err) {
      setError(err);
      return;
    }
    window.location.hash = '#/';
  };

  return (
    <div
      style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        minHeight: '100vh',
      }}
    >
      <div class="card" style={{ width: '340px' }}>
        <div
          class="card-title"
          style={{
            textAlign: 'center',
            marginBottom: '20px',
            fontSize: '18px',
            color: 'var(--accent)',
          }}
        >
          PHALANX ADMIN
        </div>
        <form onSubmit={handleSubmit}>
          <div class="form-group">
            <label>Email</label>
            <input
              type="email"
              value={email}
              onInput={(e) => {
                setEmail((e.target as HTMLInputElement).value);
              }}
              required
            />
          </div>
          <div class="form-group">
            <label>Password</label>
            <input
              type="password"
              value={password}
              onInput={(e) => {
                setPassword((e.target as HTMLInputElement).value);
              }}
              required
            />
          </div>
          {error && <p class="error-msg">{error}</p>}
          <button
            type="submit"
            class="primary"
            disabled={loading}
            style={{ width: '100%', marginTop: '8px' }}
          >
            {loading ? 'Signing in...' : 'Sign in'}
          </button>
        </form>
      </div>
    </div>
  );
}

import { useState } from 'preact/hooks';
import { apiPost } from '../hooks/useApi.js';

export function MatchCreator() {
  const [playerName, setPlayerName] = useState('Admin');
  const [opponent, setOpponent] = useState<'bot-random' | 'human'>('bot-random');
  const [rows, setRows] = useState(4);
  const [columns, setColumns] = useState(6);
  const [maxHandSize, setMaxHandSize] = useState(3);
  const [damageMode, setDamageMode] = useState<'classic' | 'cumulative'>('classic');
  const [startingLifepoints, setStartingLifepoints] = useState(20);
  const [rngSeed, setRngSeed] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const totalSlots = rows * columns;
  const initialDraw = rows * columns + columns;
  const slotsOverLimit = totalSlots > 48;

  const payload = {
    playerName,
    opponent,
    matchParams: { rows, columns, maxHandSize },
    gameOptions: { damageMode, startingLifepoints },
    ...(rngSeed ? { rngSeed: parseInt(rngSeed, 10) } : {}),
  };

  const handleSubmit = async (e: Event) => {
    e.preventDefault();
    if (slotsOverLimit) {
      setError('Total slots exceed 48. Reduce grid size.');
      return;
    }
    if (maxHandSize > columns) {
      setError('maxHandSize cannot exceed columns.');
      return;
    }
    setLoading(true);
    setError(null);
    const { data, error: err } = await apiPost<{ matchId: string }>('/admin-api/matches', payload);
    setLoading(false);
    if (err) {
      setError(err);
      return;
    }
    window.location.hash = `#/matches/${data!.matchId}`;
  };

  return (
    <div class="page">
      <h1 class="page-title">New Match</h1>
      <p class="page-subtitle">Create a match on the game server</p>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 360px', gap: '20px' }}>
        <form onSubmit={handleSubmit}>
          <div class="card">
            <div class="card-title">Players</div>
            <div class="form-group">
              <label>Player Name</label>
              <input
                value={playerName}
                onInput={(e) => {
                  setPlayerName((e.target as HTMLInputElement).value);
                }}
                required
              />
            </div>
            <div class="form-group">
              <label>Opponent</label>
              <div style={{ display: 'flex', gap: '8px' }}>
                <button
                  type="button"
                  class={opponent === 'bot-random' ? 'primary' : ''}
                  onClick={() => {
                    setOpponent('bot-random');
                  }}
                >
                  Bot Random
                </button>
                <button type="button" disabled title="Not yet implemented" style={{ opacity: 0.4 }}>
                  Bot Heuristic
                </button>
                <button
                  type="button"
                  class={opponent === 'human' ? 'primary' : ''}
                  onClick={() => {
                    setOpponent('human');
                  }}
                >
                  Human
                </button>
              </div>
            </div>
          </div>

          <div class="card" style={{ marginTop: '12px' }}>
            <div class="card-title">Grid</div>
            <div class="form-row">
              <div class="form-group">
                <label>Rows</label>
                <input
                  type="number"
                  min="1"
                  max="12"
                  value={rows}
                  onInput={(e) => {
                    setRows(parseInt((e.target as HTMLInputElement).value, 10));
                  }}
                />
              </div>
              <div class="form-group">
                <label>Columns</label>
                <input
                  type="number"
                  min="1"
                  max="12"
                  value={columns}
                  onInput={(e) => {
                    setColumns(parseInt((e.target as HTMLInputElement).value, 10));
                  }}
                />
              </div>
            </div>
            <div class="form-row">
              <div class="form-group">
                <label>Max Hand Size</label>
                <input
                  type="number"
                  min="0"
                  value={maxHandSize}
                  onInput={(e) => {
                    setMaxHandSize(parseInt((e.target as HTMLInputElement).value, 10));
                  }}
                />
              </div>
              <div class="form-group">
                <label>Initial Draw (computed)</label>
                <input value={initialDraw} disabled />
              </div>
            </div>
            {slotsOverLimit && <p class="warn-msg">Total slots ({totalSlots}) exceed 48</p>}
          </div>

          <div class="card" style={{ marginTop: '12px' }}>
            <div class="card-title">Game Options</div>
            <div class="form-row">
              <div class="form-group">
                <label>Damage Mode</label>
                <select
                  value={damageMode}
                  onChange={(e) => {
                    setDamageMode(
                      (e.target as HTMLSelectElement).value as 'classic' | 'cumulative',
                    );
                  }}
                >
                  <option value="classic">Classic</option>
                  <option value="cumulative">Cumulative</option>
                </select>
              </div>
              <div class="form-group">
                <label>Starting Lifepoints</label>
                <input
                  type="number"
                  min="1"
                  max="500"
                  value={startingLifepoints}
                  onInput={(e) => {
                    setStartingLifepoints(parseInt((e.target as HTMLInputElement).value, 10));
                  }}
                />
              </div>
            </div>
            <div class="form-group">
              <label>RNG Seed (optional)</label>
              <input
                type="number"
                placeholder="Leave blank for random"
                value={rngSeed}
                onInput={(e) => {
                  setRngSeed((e.target as HTMLInputElement).value);
                }}
              />
            </div>
          </div>

          {error && (
            <p class="error-msg" style={{ marginTop: '12px' }}>
              {error}
            </p>
          )}
          <button type="submit" class="primary" disabled={loading} style={{ marginTop: '16px' }}>
            {loading ? 'Creating...' : 'Create Match'}
          </button>
        </form>

        <div>
          <div class="card" style={{ position: 'sticky', top: '24px' }}>
            <div class="card-title">Payload Preview</div>
            <pre style={{ fontSize: '11px' }}>{JSON.stringify(payload, null, 2)}</pre>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'preact/hooks';
import { useApi } from '../hooks/useApi.js';
import { IntegrityBadge } from '../components/IntegrityBadge.js';

interface TransactionEntry {
  action: { type: string; column?: number; cardId?: unknown };
  phaseTrace: string[];
  stateHashAfter: string;
  turnHash?: string;
}

interface EventEntry {
  id: string;
  type: string;
  name: string;
  timestamp: string;
  status: string;
}

interface Match {
  id: string;
  player_1_name: string;
  player_2_name: string;
  bot_strategy: string | null;
  status: string;
  outcome: { victoryType?: string; winnerName?: string; winnerId?: string } | null;
  transaction_log: TransactionEntry[];
  event_log: { events: EventEntry[] } | null;
  event_log_fingerprint: string | null;
  config: unknown;
  created_at: string;
}

function actionDsl(action: TransactionEntry['action']): string {
  if (action.type === 'deploy') return `A:${action.column}:${String(action.cardId).slice(0, 6)}`;
  if (action.type === 'discard') return `D:${action.column}:${String(action.cardId).slice(0, 6)}`;
  if (action.type === 'reinforcement') return `R:${String(action.cardId).slice(0, 6)}`;
  if (action.type === 'pass') return 'P';
  if (action.type === 'forfeit') return 'F';
  return action.type;
}

