  const rowsInput = document.createElement('input');
  rowsInput.type = 'number';
  rowsInput.className = 'mode-select';
  rowsInput.min = String(limits.rows.min);
  rowsInput.max = String(limits.rows.max);
  rowsInput.step = '1';
