describe('Phase guards: actions rejected in wrong phases', () => {
  it('any action by non-active player is rejected', () => {
    const bf = emptyBf();
    const state = makeCombatState(bf, bf); // activePlayerIndex: 0
    const result = validateAction(state, {
      type: 'pass',
      playerIndex: 1,
