  if (allowDebugErrorRoute) {
    // ── GET /debug/error — trigger a server error for Sentry validation ──
    app.get('/debug/error', { schema: { hide: true } }, async (request, reply) =>
      traceHttpHandler('debug.error', httpTraceContext(request, reply), () => {
