        testCounter.add(1);
        throw new Error('Sentry Validation Error: Server-side trigger successful');
      }),
    );
  }

  // ── WebSocket routing ────────────────────────────────────────────
  const wsConnectionsByIp = new Map<string, number>();
  const MAX_WS_PER_IP = 10;

  app.register(async (fastify) => {
    fastify.get('/ws', { websocket: true }, async (socket, req) => {
      const clientIp = req.ip;

      // 0. Connection Limiting by IP (OWASP: DoS Prevention)
      const currentCount = wsConnectionsByIp.get(clientIp) || 0;
      if (currentCount >= MAX_WS_PER_IP) {
        app.log.warn({ clientIp }, 'WebSocket connection rejected: Too many connections from IP');
        socket.close(1008, 'Too many connections from this IP');
        return;
      }
      wsConnectionsByIp.set(clientIp, currentCount + 1);

      // 1. Optional Authentication
      let authUser: { id: string; name: string } | null = null;
      try {
        const token =
          req.cookies.phalanx_refresh ||
          req.cookies.token ||
          req.headers.authorization?.replace('Bearer ', '');
        if (token) {
          const p = fastify.jwt.verify(token);
          authUser = { id: p.id, name: p.name || `${p.gamertag}#${String(p.suffix).padStart(4, '0')}` };
        }
      } catch {
        // Auth is optional for now, so we just continue as guest
      }

      // 2. Origin Validation (OWASP: CSWSH Protection)
      const origin = req.headers.origin;
      const allowedOrigins = [
        'https://phalanxduel.fly.dev',
        'https://phalanxduel-staging.fly.dev',
        'https://play.phalanxduel.com',
        'https://phalanxduel.com',
        'http://localhost:3001',
        'http://localhost:5173', // Vite dev server
        'http://127.0.0.1:5173', // Vite dev server (IP)
      ];

      const isTest = (process.env.NODE_ENV ?? 'development') === 'test';
      if (!origin && !isTest) {
        app.log.warn({ clientIp }, 'WebSocket connection rejected: Missing Origin');
        socket.close(1008, 'Origin required');
        return;
      }

      if (origin && !allowedOrigins.includes(origin)) {
        app.log.warn({ origin, clientIp }, 'WebSocket connection rejected: Invalid Origin');
        socket.close(1008, 'Invalid Origin');
        return;
      }

      void trackProcess('ws.connection', {}, () => {
        wsConnections.add(1);

        // 3. Heartbeat (OWASP: Connection Management)
        let isAlive = true;
        socket.on('pong', () => {
          isAlive = true;
        });

        const pingInterval = setInterval(() => {
          if (!isAlive) {
            app.log.info({ clientIp }, 'Closing dead WebSocket connection (no pong)');
            socket.terminate();
            return;
          }
          isAlive = false;
          socket.ping();
        }, 30_000);

        // Rate limiting: 10 messages per second sliding window
        const MSG_LIMIT = 10;
        const WINDOW_MS = 1000;
        const timestamps: number[] = [];

        function sendMessage(msg: ServerMessage): void {
          if (socket.readyState === 1) {
            socket.send(JSON.stringify(msg));
          }
        }

        socket.on('message', (raw: RawData) => {
          // 4. Payload size limit (10KB) (OWASP: DoS Prevention)
          const size = Array.isArray(raw)
            ? raw.reduce((acc, b) => acc + b.length, 0)
            : raw instanceof ArrayBuffer
              ? raw.byteLength
              : raw.length;

          if (size > 10240) {
            app.log.warn({ size, clientIp }, 'WebSocket message rejected: Payload too large');
            socket.close(1009, 'Message too large');
            return;
          }

          // Rate limit check
          const now = Date.now();
          while (timestamps.length > 0 && timestamps[0]! <= now - WINDOW_MS) {
            timestamps.shift();
          }
          if (timestamps.length >= MSG_LIMIT) {
            sendMessage({ type: 'matchError', error: 'Too many messages', code: 'RATE_LIMITED' });
            return;
          }
          timestamps.push(now);
          const messageStr = typeof raw === 'string' ? raw : raw.toString();

          let parsed: unknown;
          try {
            parsed = JSON.parse(messageStr);
          } catch {
            sendMessage({ type: 'matchError', error: 'Invalid JSON', code: 'PARSE_ERROR' });
            return;
          }

          const result = ClientMessageSchema.safeParse(parsed);
          if (!result.success) {
            app.log.error(
              { errors: result.error.issues, parsed, clientIp },
              'Invalid Client Message',
            );
            sendMessage({
              type: 'matchError',
              error: 'Invalid message format',
              code: 'VALIDATION_ERROR',
            });
            return;
          }

          const msg = result.data;

          switch (msg.type) {
            case 'createMatch': {
              traceWsMessage('createMatch', {}, (span) => {
                try {
                  const resolvedSeed = resolveCreateMatchSeed(msg);
                  if (process.env.NODE_ENV === 'production' && resolvedSeed !== undefined) {
                    throw new MatchError(
                      'rngSeed is not allowed in production',
                      'SEED_NOT_ALLOWED',
                    );
                  }

                  const gameOptions = msg.gameOptions
                    ? {
                        damageMode: msg.gameOptions.damageMode,
                        startingLifepoints: msg.gameOptions.startingLifepoints,
                        classicDeployment: msg.gameOptions.classicDeployment,
                      }
                    : undefined;
                  const botOptions =
                    msg.opponent === 'bot-random' || msg.opponent === 'bot-heuristic'
                      ? {
                          opponent: msg.opponent,
                          botConfig: {
                            strategy: msg.opponent === 'bot-heuristic' ? ('heuristic' as const) : ('random' as const),
                            seed: Date.now(),
                          },
                        }
                      : undefined;
                  const { matchId, playerId, playerIndex } = matchManager.createMatch(
                    authUser?.name || msg.playerName,
                    socket,
                    {
                      gameOptions,
                      rngSeed: resolvedSeed,
                      botOptions,
                      matchParams: msg.matchParams,
                      userId: authUser?.id,
                      creatorIp: clientIp,
                    },
                  );
                  span.setAttribute('match.id', matchId);
                  matchesActive.add(1);
                  sendMessage({ type: 'matchCreated', matchId, playerId, playerIndex });
                  // For bot matches the game is already initialized;
                  // broadcast state after matchCreated so the client sets playerIndex first.
                  if (botOptions) {
                    matchManager.broadcastMatchState(matchId);
                  }
                } catch (err) {
                  if (err instanceof MatchError) {
                    sendMessage({ type: 'matchError', error: err.message, code: err.code });
                  } else {
                    const error = err instanceof Error ? err.message : 'Unknown error';
                    sendMessage({ type: 'matchError', error, code: 'CREATE_FAILED' });
                  }
                }
              });
              break;
            }

            case 'joinMatch': {
              traceWsMessage('joinMatch', { 'match.id': msg.matchId }, async (span) => {
                try {
                  const { playerId, playerIndex } = await matchManager.joinMatch(
                    msg.matchId,
                    authUser?.name || msg.playerName,
                    socket,
                    authUser?.id,
                  );
                  span.setAttribute('player.id', playerId);
                  // Send matchJoined to joining player BEFORE broadcasting state
                  sendMessage({
                    type: 'matchJoined',
                    matchId: msg.matchId,
                    playerId,
                    playerIndex,
                  });
                  matchManager.broadcastMatchState(msg.matchId);
                } catch (err) {
                  if (err instanceof MatchError) {
                    sendMessage({ type: 'matchError', error: err.message, code: err.code });
                  } else {
                    const error = err instanceof Error ? err.message : 'Unknown error';
                    sendMessage({ type: 'matchError', error, code: 'JOIN_FAILED' });
                  }
                }
              });
              break;
            }

            case 'watchMatch': {
              traceWsMessage('watchMatch', { 'match.id': msg.matchId }, async (span) => {
                try {
                  const { spectatorId } = await matchManager.watchMatch(msg.matchId, socket);
                  span.setAttribute('spectator.id', spectatorId);
                  sendMessage({ type: 'spectatorJoined', matchId: msg.matchId, spectatorId });
                  // Broadcast state after sending spectatorJoined so client sets isSpectator first
                  matchManager.broadcastMatchState(msg.matchId);
                } catch (err) {
                  if (err instanceof MatchError) {
                    sendMessage({ type: 'matchError', error: err.message, code: err.code });
                  } else {
                    const error = err instanceof Error ? err.message : 'Unknown error';
                    sendMessage({ type: 'matchError', error, code: 'WATCH_FAILED' });
                  }
                }
              });
              break;
            }

            case 'authenticate': {
              try {
                const authPayload = fastify.jwt.verify(msg.token);
                const displayName = formatGamertag(authPayload.gamertag, authPayload.suffix);
                authUser = { id: authPayload.id, name: displayName };
                matchManager.updatePlayerIdentity(socket, authPayload.id, displayName);
                sendMessage({
                  type: 'authenticated',
                  user: { id: authPayload.id, name: displayName, elo: 0 },
                });
              } catch {
                sendMessage({ type: 'auth_error', error: 'Invalid token' });
              }
              break;
            }

            case 'action': {
              const socketInfo = matchManager.socketMap.get(socket);
              if (!socketInfo || socketInfo.isSpectator) {
                sendMessage({
                  type: 'matchError',
                  error: 'Not connected to a match',
                  code: 'NOT_IN_MATCH',
                });
                return;
              }

              traceWsMessage(
                'action',
                {
                  'match.id': msg.matchId,
                  'player.id': socketInfo.playerId,
                  'action.type': msg.action.type,
                },
                async (_span) => {
                  await trackProcess(
                    'game.action',
                    {
                      'action.type': msg.action.type,
                      'match.id': msg.matchId,
                    },
                    async () => {
                      const start = performance.now();

                      try {
                        await matchManager.handleAction(
                          msg.matchId,
                          socketInfo.playerId,
                          msg.action,
                        );
                        actionsTotal.add(1, { 'action.type': msg.action.type });
                        actionsDurationMs.record(performance.now() - start);

                        // Emit the transaction log entry to the Pino log stream so the
                        // game can be tailed in real-time: tail -f logs/server.log | jq .
                        const txEntry = matchManager.matches
                          .get(msg.matchId)
                          ?.state?.transactionLog?.at(-1);
                        if (txEntry) {
                          const loggedDetails =
                            txEntry.action.type === 'deploy' && txEntry.details.type === 'pass'
                              ? { ...txEntry.details, type: 'deploy' as const }
                              : txEntry.details;
                          app.log.info(
                            {
                              event: 'game_action',
                              matchId: msg.matchId,
                              playerId: socketInfo.playerId,
                              turn: txEntry.sequenceNumber,
                              action: txEntry.action.type,
                              details: loggedDetails,
                              stateHash: txEntry.stateHashAfter,
                            },
                            `game:${txEntry.action.type} t${txEntry.sequenceNumber}`,
                          );
                        }
                      } catch (err) {
                        actionsDurationMs.record(performance.now() - start);
                        if (err instanceof ActionError) {
                          sendMessage({
                            type: 'actionError',
                            error: err.message,
                            code: err.code,
                          });
                        } else if (err instanceof MatchError) {
                          sendMessage({ type: 'matchError', error: err.message, code: err.code });
                        } else {
                          const error = err instanceof Error ? err.message : 'Unknown error';
                          sendMessage({
                            type: 'actionError',
                            error,
                            code: 'ACTION_FAILED',
                          });
                        }
                        throw err; // Re-throw so trackProcess records the error
                      }
                    },
                  );
                },
              );
              break;
            }
          }
        });

        socket.on('close', () => {
          clearInterval(pingInterval);
          wsConnections.add(-1);
          matchManager.handleDisconnect(socket);

          // Decrement IP-based connection counter
          const count = wsConnectionsByIp.get(clientIp) || 1;
          if (count <= 1) {
            wsConnectionsByIp.delete(clientIp);
          } else {
            wsConnectionsByIp.set(clientIp, count - 1);
          }

          app.log.info({ clientIp }, 'WebSocket client disconnected');
        });
      });
    });
  });

  // Match cleanup: remove stale matches every 60 seconds
  matchManager.onMatchRemoved = () => { matchesActive.add(-1); };
  const cleanupInterval = setInterval(() => {
    void trackProcess('match.cleanup', {}, () => {
      const removed = matchManager.cleanupMatches();
      if (removed > 0) {
        app.log.info({ removed }, 'Cleaned up stale matches');
      }
    });
  }, 60_000);
  app.addHook('onClose', () => { clearInterval(cleanupInterval); });

  // Expose matchManager for testing
  app.decorate('matchManager', matchManager);

  return app;
}

import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import postgres from 'postgres';

const __dirname = dirname(fileURLToPath(import.meta.url));
const JOURNAL_PATH = resolve(__dirname, '../../drizzle/meta/_journal.json');

/**
 * Compares applied migrations in the DB against the local Drizzle journal.
 * Exits the process with code 1 if any migrations are pending.
 * Silently passes when DATABASE_URL is not set (guest-only mode).
 */
export async function checkPendingMigrations(): Promise<void> {
  const connectionString = process.env.DATABASE_URL;
  if (!connectionString) return;

  const journal = JSON.parse(readFileSync(JOURNAL_PATH, 'utf8')) as {
    entries: unknown[];
  };
  const expected = journal.entries.length;

  const sql = postgres(connectionString, { max: 1, connect_timeout: 5 });
  try {
    const tableExists = await sql`
      SELECT count(*)::int AS count
      FROM information_schema.tables
      WHERE table_schema = 'drizzle'
        AND table_name = '__drizzle_migrations'
    `;

    if (tableExists[0]!.count === 0) {
      console.error(
        `\n❌ No migrations applied (${expected} pending).\n` +
          `   Run: pnpm --filter @phalanxduel/server db:migrate\n`,
      );
      process.exit(1);
    }

    const applied = await sql`
      SELECT count(*)::int AS count FROM "drizzle"."__drizzle_migrations"
    `;

    const appliedCount = applied[0]!.count as number;
    if (appliedCount < expected) {
      const pending = expected - appliedCount;
      console.error(
        `\n❌ ${pending} pending migration(s) (${appliedCount}/${expected} applied).\n` +
          `   Run: pnpm --filter @phalanxduel/server db:migrate\n`,
      );
      process.exit(1);
    }
  } finally {
    await sql.end();
  }
}

import { db } from './index.js';
import { matches, transactionLogs } from './schema.js';
import { desc, eq, asc } from 'drizzle-orm';
import type { MatchInstance } from '../match.js';
import type {
  GameState,
  Action,
  MatchEventLog,
  TransactionLogEntry,
  PhalanxEvent,
} from '@phalanxduel/shared';
import type { GameConfig } from '@phalanxduel/engine';
import { traceDbQuery } from './observability.js';

export interface MatchSummary {
  matchId: string;
  playerIds: (string | null)[];
  playerNames: string[];
  winnerIndex: number | null;
  victoryType: string | null;
  turnCount: number | null;
  fingerprint: string | null;
  createdAt: string;
  completedAt: string;
}

export class MatchRepository {
  async saveMatch(match: MatchInstance): Promise<void> {
    const database = db;
    if (!database) return;
    if (!match.config) return;

    const payload = {
      id: match.matchId,
      player1Id: match.players[0]?.userId ?? null,
      player2Id: match.players[1]?.userId ?? null,
      player1Name: match.players[0]?.playerName ?? 'Unknown',
      player2Name: match.players[1]?.playerName ?? 'Unknown',
      botStrategy: match.botStrategy ?? null,
      config: match.config,
      state: match.state,
      actionHistory: match.actionHistory,
      transactionLog: match.state?.transactionLog ?? [],
      outcome: match.state?.outcome ?? null,
      status: (match.state?.phase === 'gameOver' ? 'completed' : 'active') as
        | 'pending'
        | 'active'
        | 'completed'
        | 'cancelled',
      updatedAt: new Date(),
    };

    try {
      await traceDbQuery(
        'db.matches.upsert',
        {
          operation: 'UPSERT',
          table: 'matches',
        },
        () =>
          database
            .insert(matches)
            .values({
              ...payload,
              createdAt: new Date(match.createdAt),
            })
            .onConflictDoUpdate({
              target: matches.id,
              set: payload,
            }),
      );
    } catch (err) {
      console.error('Failed to save match to database:', err);
    }
  }

  async getCompletedMatches(page: number, limit: number): Promise<MatchSummary[]> {
    const database = db;
    if (!database) return [];

    try {
      const offset = (page - 1) * limit;
      const rows = await traceDbQuery(
        'db.matches.select_completed',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select({
              id: matches.id,
              player1Id: matches.player1Id,
              player2Id: matches.player2Id,
              player1Name: matches.player1Name,
              player2Name: matches.player2Name,
              outcome: matches.outcome,
              eventLogFingerprint: matches.eventLogFingerprint,
              createdAt: matches.createdAt,
              updatedAt: matches.updatedAt,
            })
            .from(matches)
            .where(eq(matches.status, 'completed'))
            .orderBy(desc(matches.createdAt))
            .limit(limit)
            .offset(offset),
      );

      return rows.map((row) => {
        const outcome = row.outcome as {
          winnerIndex?: number | null;
          victoryType?: string | null;
          turnNumber?: number | null;
        } | null;
        return {
          matchId: row.id,
          playerIds: [row.player1Id ?? null, row.player2Id ?? null],
          playerNames: [row.player1Name, row.player2Name],
          winnerIndex: outcome?.winnerIndex ?? null,
          victoryType: outcome?.victoryType ?? null,
          turnCount: outcome?.turnNumber ?? null,
          fingerprint: row.eventLogFingerprint ?? null,
          createdAt: row.createdAt.toISOString(),
          completedAt: row.updatedAt.toISOString(),
        };
      });
    } catch (err) {
      console.error('Failed to get completed matches from database:', err);
      return [];
    }
  }

  async saveEventLog(matchId: string, log: MatchEventLog): Promise<void> {
    const database = db;
    if (!database) return;

    try {
      await traceDbQuery(
        'db.matches.update_event_log',
        { operation: 'UPDATE', table: 'matches' },
        () =>
          database
            .update(matches)
            .set({ eventLog: log, eventLogFingerprint: log.fingerprint })
            .where(eq(matches.id, matchId)),
      );
    } catch (err) {
      console.error('Failed to save event log to database:', err);
    }
  }

  async getEventLog(matchId: string): Promise<MatchEventLog | null> {
    const database = db;
    if (!database) return null;

    try {
      const result = await traceDbQuery(
        'db.matches.select_event_log',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select({ eventLog: matches.eventLog })
            .from(matches)
            .where(eq(matches.id, matchId))
            .limit(1),
      );
      if (result.length === 0 || !result[0]!.eventLog) return null;
      return result[0]!.eventLog as MatchEventLog;
    } catch (err) {
      console.error('Failed to get event log from database:', err);
      return null;
    }
  }

  async getMatch(matchId: string): Promise<MatchInstance | null> {
    const database = db;
    if (!database) return null;

    try {
      const result = await traceDbQuery(
        'db.matches.select_by_id',
        {
          operation: 'SELECT',
          table: 'matches',
        },
        () => database.select().from(matches).where(eq(matches.id, matchId)).limit(1),
      );
      if (result.length === 0) return null;

      const row = result[0]!;
      // Reconstituting MatchInstance from DB row
      // Note: sockets cannot be recovered from DB
      return {
        matchId: row.id,
        players: [
          row.player1Name
            ? {
                playerId: 'recovered-p1',
                playerName: row.player1Name,
                playerIndex: 0,
                userId: row.player1Id || undefined,
                socket: null,
              }
            : null,
          row.player2Name
            ? {
                playerId: 'recovered-p2',
                playerName: row.player2Name,
                playerIndex: 1,
                userId: row.player2Id || undefined,
                socket: null,
              }
            : null,
        ],
        spectators: [],
        state: row.state as GameState,
        config: row.config as GameConfig,
        actionHistory: row.actionHistory as Action[],
        lastPreState: null,
        lifecycleEvents: [],
        createdAt: row.createdAt.getTime(),
        lastActivityAt: row.updatedAt.getTime(),
        botStrategy: row.botStrategy ?? undefined,
      };
    } catch (err) {
      console.error('Failed to get match from database:', err);
      return null;
    }
  }

  async saveTransactionLogEntry(
    matchId: string,
    sequenceNumber: number,
    entry: TransactionLogEntry,
    events: PhalanxEvent[],
  ): Promise<void> {
    const database = db;
    if (!database) return;

    try {
      await traceDbQuery(
        'db.transaction_logs.insert',
        { operation: 'INSERT', table: 'transaction_logs' },
        () =>
          database.insert(transactionLogs).values({
            matchId,
            sequenceNumber,
            action: entry.action,
            stateHashBefore: entry.stateHashBefore,
            stateHashAfter: entry.stateHashAfter,
            events,
          }),
      );
    } catch (err) {
      console.error('Failed to save transaction log entry:', err);
    }
  }

  async getTransactionLog(matchId: string): Promise<TransactionLogEntry[]> {
    const database = db;
    if (!database) return [];

    try {
      const rows = await traceDbQuery(
        'db.transaction_logs.select_by_match',
        { operation: 'SELECT', table: 'transaction_logs' },
        () =>
          database
            .select()
            .from(transactionLogs)
            .where(eq(transactionLogs.matchId, matchId))
            .orderBy(asc(transactionLogs.sequenceNumber)),
      );

      return rows.map((row) => ({
        sequenceNumber: row.sequenceNumber,
        action: row.action as Action,
        stateHashBefore: row.stateHashBefore,
        stateHashAfter: row.stateHashAfter,
        timestamp: row.createdAt.toISOString(),
        details:
          (row.events as PhalanxEvent[]).find((e) => e.type === 'functional_update')?.payload || {},
      })) as unknown as TransactionLogEntry[];
    } catch (err) {
      console.error('Failed to get transaction log:', err);
      return [];
    }
  }
}

import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { drizzle } from 'drizzle-orm/postgres-js';
import { migrate } from 'drizzle-orm/postgres-js/migrator';
import postgres from 'postgres';
import '../loadEnv.js';

const connectionString = process.env.DATABASE_URL;

if (!connectionString) {
  console.error('DATABASE_URL is not set');
  process.exit(1);
}

// Resolve drizzle/ relative to the server package root, not CWD.
// In dev: server/src/db/migrate.ts → ../../drizzle
// In prod: server/dist/db/migrate.js → ../../drizzle
const __dirname = dirname(fileURLToPath(import.meta.url));
const migrationsFolder = resolve(__dirname, '../../drizzle');

const sql = postgres(connectionString, { max: 1 });
const db = drizzle(sql);

async function main() {
  console.log(`Running migrations from ${migrationsFolder}...`);
  await migrate(db, { migrationsFolder });
  console.log('Migrations complete!');
  await sql.end();
}

main().catch((err) => {
  console.error('Migration failed:', err);
  process.exit(1);
});

import './instrument.js';
import { buildApp } from './app.js';
import { checkPendingMigrations } from './db/check-migrations.js';

async function main(): Promise<void> {
  await checkPendingMigrations();
  const app = await buildApp();
  const port = parseInt(process.env.PHALANX_SERVER_PORT || '3001', 10);
  const host = process.env.HOST ?? '0.0.0.0';

  await app.listen({ port, host });
  console.log(`Phalanx Duel server listening on http://${host}:${port}`);

  // ── Graceful Shutdown Handler ────────────────────────────────────
  // When the container receives SIGTERM (Kubernetes, Docker stop, Fly.io deploy),
  // close the server gracefully, allowing in-flight requests/WebSocket connections
  // to complete within a timeout window.
  //
  // Timeline:
  // 1. Signal received → Stop accepting NEW connections
  // 2. Close server → Wait for in-flight requests (30s timeout)
  // 3. Exit → Process terminates, container restarts
  const signals = ['SIGTERM', 'SIGINT'];

  signals.forEach((signal) => {
    process.on(signal, async () => {
      app.log.info(`Received ${signal}, initiating graceful shutdown...`);

      try {
        // Stop accepting new connections and close the server
        // Existing WebSocket connections and HTTP requests get time to complete
        await app.close();

        app.log.info('Server closed successfully, all connections drained');
        process.exit(0);
      } catch (err) {
        app.log.error(
          { error: err instanceof Error ? err.message : String(err) },
          'Error during graceful shutdown',
        );
        process.exit(1);
      }
    });
  });

  // Handle uncaught exceptions → log and exit
  process.on('uncaughtException', (err) => {
    app.log.error(
      { error: err instanceof Error ? err.message : String(err) },
      'Uncaught exception, exiting',
    );
    process.exit(1);
  });

  // Handle unhandled promise rejections → log and exit
  process.on('unhandledRejection', (reason) => {
    app.log.error(
      { reason: reason instanceof Error ? reason.message : String(reason) },
      'Unhandled rejection, exiting',
    );
    process.exit(1);
  });
}

main().catch((err) => {
  console.error('Failed to start server:', err);
  process.exit(1);
});

import './loadEnv.js';
import * as Sentry from '@sentry/node';
import { hostname } from 'node:os';
import { SCHEMA_VERSION } from '@phalanxduel/shared';
import { metrics } from '@opentelemetry/api';
import { logs, SeverityNumber } from '@opentelemetry/api-logs';
import { BatchSpanProcessor, NodeTracerProvider } from '@opentelemetry/sdk-trace-node';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-http';
import { OTLPLogExporter } from '@opentelemetry/exporter-logs-otlp-http';
import { MeterProvider, PeriodicExportingMetricReader } from '@opentelemetry/sdk-metrics';
import { BatchLogRecordProcessor, LoggerProvider } from '@opentelemetry/sdk-logs';
import { OTLPMetricExporter } from '@opentelemetry/exporter-metrics-otlp-http';
import { resourceFromAttributes } from '@opentelemetry/resources';
import { ATTR_SERVICE_NAME } from '@opentelemetry/semantic-conventions';

interface MeterProviderWithAddMetricReader {
  addMetricReader(reader: PeriodicExportingMetricReader): void;
}

function hasAddMetricReader(value: unknown): value is MeterProviderWithAddMetricReader {
  return (
    typeof value === 'object' &&
    value !== null &&
    typeof Reflect.get(value, 'addMetricReader') === 'function'
  );
}

function normalizeOtlpEndpoint(endpoint: string): string {
  return endpoint
    .trim()
    .replace(/\/+$/u, '')
    .replace(/\/v1\/(traces|metrics|logs)$/u, '');
}

function envFlagEnabled(value: string | undefined): boolean {
  return value === '1' || value?.toLowerCase() === 'true';
}

const isProduction = process.env.NODE_ENV === 'production';
const sentryDsn = process.env.SENTRY_DSN;
// OTel collector endpoint with default to localhost:4318 (local development)
const otlpEndpointRaw = process.env.OTEL_EXPORTER_OTLP_ENDPOINT || 'http://localhost:4318';
const otlpEndpoint = normalizeOtlpEndpoint(otlpEndpointRaw);
const localSentryEnabled = envFlagEnabled(process.env.PHALANX_ENABLE_LOCAL_SENTRY);
const sentryEnabled = !!sentryDsn && (isProduction || localSentryEnabled);
const otlpConsoleLogsEnabled =
  process.env.OTEL_CONSOLE_LOGS_ENABLED === '1' ||
  process.env.OTEL_CONSOLE_LOGS_ENABLED?.toLowerCase() === 'true';
const serviceName = process.env.OTEL_SERVICE_NAME?.trim() || 'phalanxduel';
process.env.OTEL_SERVICE_NAME ??= serviceName;
const resource = resourceFromAttributes({
  [ATTR_SERVICE_NAME]: serviceName,
});

const integrations = [Sentry.consoleLoggingIntegration({ levels: ['log', 'warn', 'error'] })];

// Create OTLP trace exporter (primary telemetry path)
let traceExporter: OTLPTraceExporter | undefined;
try {
  traceExporter = new OTLPTraceExporter({
    url: `${otlpEndpoint}/v1/traces`,
  });
} catch (error) {
  console.warn(
    `[instrument.ts] Failed to initialize OTLP trace exporter at ${otlpEndpoint}:`,
    error instanceof Error ? error.message : error,
  );
}

if (!isProduction) {
  integrations.push(Sentry.spotlightIntegration());
}

// Try to load profiling integration if available
try {
  const { nodeProfilingIntegration } = await import('@sentry/profiling-node');
  if (nodeProfilingIntegration) {
    integrations.push(nodeProfilingIntegration());
  }
} catch {
  // Silently fail profiling if binary is missing or incompatible
}

// Initialize Sentry for error/exception capturing only (not span export).
// Spans are exported via OTLP to the local collector instead.
if (sentryEnabled) {
  Sentry.init({
    dsn: sentryDsn,
    release: process.env.SENTRY_RELEASE || `phalanxduel@${SCHEMA_VERSION}`,
    // The default Fastify integration from Sentry registers @fastify/otel, which
    // wraps route handlers assuming (request, reply) signature. This crashes on
    // WebSocket routes where the handler receives (socket, request) instead.
    // Use the function form so we actually replace defaults rather than merging.
    integrations: (defaults) => [...defaults.filter((i) => i.name !== 'Fastify'), ...integrations],
    // Structured log ingestion via Sentry.logger.* (errors and exceptions)
    enableLogs: true,
    // NOTE: Sentry span export is disabled. All spans go to OTLP collector.
    // Set tracesSampleRate=0 to prevent Sentry from sampling spans, since
    // we're using OTLP as the primary tracing backend.
    tracesSampleRate: 0,
    // Continuous profiling (SDK v8+ API)
    profileSessionSampleRate: process.env.SENTRY_PROFILES_SAMPLE_RATE
      ? parseFloat(process.env.SENTRY_PROFILES_SAMPLE_RATE)
      : 1.0,
    profileLifecycle: 'trace',
    environment: process.env.APP_ENV || process.env.NODE_ENV || 'development',
    debug: !isProduction && !!process.env.SENTRY_DEBUG,
    sendDefaultPii: true,

    initialScope: {
      tags: {
        'host.name': process.env.FLY_MACHINE_ID || hostname(),
        'cloud.provider': process.env.FLY_APP_NAME ? 'fly_io' : 'local',
        'cloud.region': process.env.FLY_REGION || 'unknown',
      },
    },
    // DO NOT dual-export spans to Sentry. OTLP is the primary tracing backend.
  });
} else {
  console.log('[instrument.ts] Sentry not enabled. Using OTLP for all telemetry.');
}

// ── OTLP Export Integration ─────────────────────────────────────────────────
// Primary telemetry backend: sends traces, metrics, and logs to local OTel collector.
// The collector (running on localhost:4318 by default) handles forwarding to
// configured backends (Sentry, Datadog, etc.) via its own configuration.
//
// Architecture:
//   app → OTLP exporter → localhost:4318 (OTel Collector) → backends
//
try {
  const metricExporter = new OTLPMetricExporter({
    url: `${otlpEndpoint}/v1/metrics`,
  });
  const metricReader = new PeriodicExportingMetricReader({
    exporter: metricExporter,
    exportIntervalMillis: 5000,
  });

  if (sentryEnabled && traceExporter) {
    // Sentry enabled for errors/exceptions. Attach OTLP metric exporter to Sentry's meter provider.
    const meterProvider = metrics.getMeterProvider() as unknown;
    if (hasAddMetricReader(meterProvider)) {
      meterProvider.addMetricReader(metricReader);
    } else {
      const fallbackMeterProvider = new MeterProvider({
        resource,
        readers: [metricReader],
      });
      metrics.setGlobalMeterProvider(fallbackMeterProvider);
    }
  } else if (traceExporter) {
    // OTLP-only mode (no Sentry): register standalone OpenTelemetry SDK providers.
    const tracerProvider = new NodeTracerProvider({
      resource,
      spanProcessors: [new BatchSpanProcessor(traceExporter)],
    });
    tracerProvider.register();

    const meterProvider = new MeterProvider({
      resource,
      readers: [metricReader],
    });
    metrics.setGlobalMeterProvider(meterProvider);
  } else {
    console.error(
      '[instrument.ts] OTLP endpoint configured but trace exporter initialization failed. ' +
        'Telemetry will not be exported.',
    );
  }
} catch (error) {
  console.error(
    '[instrument.ts] Failed to initialize OTLP metric exporter:',
    error instanceof Error ? error.message : error,
  );
}

// ── OTLP Console Log Forwarding (Opt-in) ────────────────────────────────────
// Disabled by default to avoid behavior changes. Enable with:
//   OTEL_CONSOLE_LOGS_ENABLED=1
if (otlpEndpoint && otlpConsoleLogsEnabled) {
  const CONSOLE_PATCH_FLAG = Symbol.for('phalanx.otel.console.patched');
  const globalObj = globalThis as Record<symbol, boolean>;

  if (!globalObj[CONSOLE_PATCH_FLAG]) {
    globalObj[CONSOLE_PATCH_FLAG] = true;

    const logExporter = new OTLPLogExporter({
      url: `${otlpEndpoint}/v1/logs`,
    });

    const loggerProvider = new LoggerProvider({
      resource,
      processors: [new BatchLogRecordProcessor(logExporter)],
    });
    logs.setGlobalLoggerProvider(loggerProvider);

    const logger = loggerProvider.getLogger('node.console', '1.0.0');

    const toMessage = (args: unknown[]): string =>
      args
        .map((arg) => {
          if (typeof arg === 'string') return arg;
          if (arg instanceof Error) return arg.stack ?? arg.message;
          try {
            return JSON.stringify(arg);
          } catch {
            return String(arg);
          }
        })
        .join(' ');

    const emit = (severityNumber: SeverityNumber, severityText: string, args: unknown[]) => {
      try {
        logger.emit({
          severityNumber,
          severityText,
          body: toMessage(args),
          attributes: {},
        });
      } catch {
        // Never break runtime behavior if log export fails.
      }
    };

    const originalConsole = {
      log: console.log,
      info: console.info,
      warn: console.warn,
      error: console.error,
    };

    console.log = (...args: unknown[]) => {
      emit(SeverityNumber.INFO, 'INFO', args);
      originalConsole.log.apply(console, args);
    };

    console.info = (...args: unknown[]) => {
      emit(SeverityNumber.INFO, 'INFO', args);
      originalConsole.info.apply(console, args);
    };

    console.warn = (...args: unknown[]) => {
      emit(SeverityNumber.WARN, 'WARN', args);
      originalConsole.warn.apply(console, args);
    };

    console.error = (...args: unknown[]) => {
      emit(SeverityNumber.ERROR, 'ERROR', args);
      originalConsole.error.apply(console, args);
    };

    const flushLogs = async () => {
      try {
        await loggerProvider.forceFlush();
      } catch {
        // Ignore flush errors on shutdown.
      }
    };
    process.once('beforeExit', () => {
      void flushLogs();
    });
  }
}

import { existsSync, readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parseEnv } from 'node:util';

const RUNTIME_UNSAFE_ENV_KEYS = new Set(['NODE_OPTIONS']);
const EXTERNALLY_DEFINED_ENV_KEYS = new Set(Object.keys(process.env));

function loadEnvFile(path: string, overrideExisting: boolean): void {
  if (!existsSync(path)) return;

  const raw = readFileSync(path, 'utf8');
  const parsed = parseEnv(raw);

  for (const [key, value] of Object.entries(parsed)) {
    // NODE_OPTIONS can crash worker-based subsystems (e.g. pino transports)
    // when injected after process boot. Respect only externally provided values.
    if (RUNTIME_UNSAFE_ENV_KEYS.has(key)) continue;

    // Let shell/runner-provided env win over file values.
    if (overrideExisting && EXTERNALLY_DEFINED_ENV_KEYS.has(key)) continue;

    if (overrideExisting || process.env[key] === undefined) {
      process.env[key] = value;
    }
  }
}

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(here, '../..');

// 1. Determine environment (APP_ENV > NODE_ENV > local)
const appEnv =
  process.env.APP_ENV || (process.env.NODE_ENV === 'production' ? 'production' : 'local');

// 2. Load hierarchy
// Base .env (Always loaded first as defaults)
loadEnvFile(resolve(repoRoot, '.env'), false);

// Environment-specific .env (e.g. .env.staging, .env.production, .env.test)
// These OVERRIDE base .env defaults
if (appEnv !== 'local') {
  loadEnvFile(resolve(repoRoot, `.env.${appEnv}`), true);
}

// Local developer overrides (Global for all local envs)
loadEnvFile(resolve(repoRoot, '.env.local'), true);

// Environment-specific local overrides (e.g. .env.staging.local)
loadEnvFile(resolve(repoRoot, `.env.${appEnv}.local`), true);

