      --surf2:  #111820;
      --border: #192433;
      --text:   #b0c4d4;
      --muted:  #354f63;
      --amber:  #e8921a;
      --cyan:   #3dc9b0;
      --green:  #38c172;
      --orange: #e87c2a;
      --red:    #e85252;
    }

    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      background: var(--bg);
      color: var(--text);
      font-family: 'IBM Plex Mono', monospace;
      font-size: 12.5px;
      line-height: 1.55;
      min-height: 100vh;
    }

    .header {
      background: var(--surf);
      border-bottom: 1px solid var(--border);
      padding: 18px 28px 14px;
      position: sticky;
      top: 0;
      z-index: 20;
      display: flex;
      align-items: baseline;
      gap: 0;
      flex-wrap: wrap;
    }

    .title {
      font-family: 'Barlow Condensed', sans-serif;
      font-size: 22px;
      font-weight: 700;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      color: var(--amber);
      margin-right: 18px;
      flex-shrink: 0;
    }

    .meta-pills { display: flex; gap: 6px; flex-wrap: wrap; align-items: center; }

    .pill {
      font-size: 10px;
      letter-spacing: 0.06em;
      color: var(--muted);
      border: 1px solid var(--border);
      border-radius: 2px;
      padding: 2px 8px;
      white-space: nowrap;
    }

    .pill b { color: var(--text); font-weight: 400; }

    .col-header {
      display: grid;
