/**
 * Game-specific telemetry and observability instrumentation.
 * Uses OpenTelemetry for spans/metrics and Sentry for errors/breadcrumbs.
 */

import * as Sentry from '@sentry/node';
import {
  TelemetryName,
  TelemetryAttribute,
  type GameState,
  type Action,
  type PhalanxTurnResult,
} from '@phalanxduel/shared';
import { createCounter, createHistogram, withActiveSpan } from './observability.js';

const gameOutcomeCounter = createCounter('game.outcome', {
  description: 'Completed games partitioned by victory type and winner.',
});
const gameOutcomeTurnHistogram = createHistogram('game.outcome.turn_number', {
  description: 'Turn count distribution for completed games.',
});

export class GameTelemetry {
  /**
   * Wrap a game action execution in an active OTel span.
   */
  static async recordAction(
    matchId: string,
    action: Action,
    execute: () => Promise<PhalanxTurnResult> | PhalanxTurnResult,
  ): Promise<PhalanxTurnResult> {
    const spanName =
      (typeof TelemetryName !== 'undefined' && TelemetryName.SPAN_GAME_ACTION) || 'game.action';
    return withActiveSpan(
      spanName,
      {
        attributes: {
          [TelemetryAttribute?.MATCH_ID || 'game.match_id']: matchId,
          [TelemetryAttribute?.ACTION_TYPE || 'game.action.type']: action.type,
          'phalanx.span.op': 'game.logic',
          ...(action.type !== 'system:init'
            ? { [TelemetryAttribute?.PLAYER_INDEX || 'game.player_index']: action.playerIndex }
            : {}),
        },
      },
      async (span) => {
        try {
          const result = await execute();

          span.setAttributes({
            [(typeof TelemetryAttribute !== 'undefined' && TelemetryAttribute.TURN_NUMBER) ||
            'game.turn_number']: result.postState.turnNumber,
            [(typeof TelemetryAttribute !== 'undefined' && TelemetryAttribute.PHASE) ||
            'game.phase']: result.postState.phase,
          });

          if (result.postState.phase === 'gameOver' && result.postState.outcome) {
            this.recordVictory(result.postState);
          }

          return result;
        } catch (error) {
          Sentry.captureException(error, {
            extra: { matchId, action },
          });
          throw error;
        }
      },
    );
  }

  /**
   * Record phase start/end as breadcrumbs or events.
   */
  static recordPhaseTransition(matchId: string, from: string, to: string) {
    Sentry.addBreadcrumb({
      category: 'game.phase',
      message: `Transition: ${from} -> ${to}`,
      data: { matchId, from, to },
      level: 'info',
    });
  }

  /**
   * Record game outcome as custom metrics.
   *
   * Uses metrics — not captureEvent — so outcomes appear on dashboards and
   * feed SLO alerts rather than polluting the Sentry issue tracker.
   *
   * Metrics emitted:
   *   game.outcome              — increment by victory_type (SLI: outcome distribution)
   *   game.outcome.turn_number  — distribution by victory_type (SLI: game length)
   */
  static recordVictory(finalState: GameState) {
    const outcome = finalState.outcome;
    if (!outcome) return;

    gameOutcomeCounter.add(1, {
      victory_type: outcome.victoryType,
      winner: String(outcome.winnerIndex),
    });
    gameOutcomeTurnHistogram.record(outcome.turnNumber, {
      victory_type: outcome.victoryType,
    });
  }
}

import { SpanKind, type Attributes, type Span } from '@opentelemetry/api';
import type { FastifyReply, FastifyRequest } from 'fastify';
import {
  ATTR_HTTP_REQUEST_METHOD,
  ATTR_HTTP_RESPONSE_STATUS_CODE,
  ATTR_HTTP_ROUTE,
  ATTR_NETWORK_PROTOCOL_NAME,
  ATTR_SERVER_ADDRESS,
  ATTR_SERVER_PORT,
  ATTR_URL_PATH,
} from '@opentelemetry/semantic-conventions';
import { withActiveSpan } from './observability.js';

interface HttpTraceOptions {
  attributes?: Attributes;
  getStatusCode?: () => number | undefined;
}

function parseHostHeader(hostHeader: string | undefined): {
  address?: string;
  port?: number;
} {
  if (!hostHeader) return {};

  const host = hostHeader.trim();
  if (!host) return {};

  const parsed = host.startsWith('[')
    ? /^(\[[^\]]+\])(?::(\d+))?$/u.exec(host)
    : /^([^:]+)(?::(\d+))?$/u.exec(host);

  if (!parsed) {
    return { address: host };
  }

  return {
    address: parsed[1]!,
    port: parsed[2] ? Number(parsed[2]) : undefined,
  };
}

export function httpRequestAttributes(
  request: Pick<FastifyRequest, 'headers' | 'hostname' | 'method' | 'routeOptions' | 'url'>,
  extraAttributes: Attributes = {},
): Attributes {
  const route = request.routeOptions.url;
  const path = route || request.url.split('?')[0] || request.url;
  const host = parseHostHeader(request.headers.host);

  return {
    [ATTR_HTTP_REQUEST_METHOD]: request.method,
    [ATTR_HTTP_ROUTE]: route,
    [ATTR_NETWORK_PROTOCOL_NAME]: 'http',
    [ATTR_SERVER_ADDRESS]: host.address ?? request.hostname,
    ...(host.port !== undefined ? { [ATTR_SERVER_PORT]: host.port } : {}),
    [ATTR_URL_PATH]: path,
    ...extraAttributes,
  };
}

export function httpTraceContext(
  request: Pick<FastifyRequest, 'headers' | 'hostname' | 'method' | 'routeOptions' | 'url'>,
  reply: Pick<FastifyReply, 'statusCode'>,
  extraAttributes: Attributes = {},
): HttpTraceOptions {
  return {
    attributes: httpRequestAttributes(request, extraAttributes),
    getStatusCode: () => reply.statusCode,
  };
}

function isHttpTraceOptions(value: Attributes | HttpTraceOptions): value is HttpTraceOptions {
  return 'attributes' in value || 'getStatusCode' in value;
}

/**
 * Wraps a WebSocket message handler in an OpenTelemetry span.
 * Use this for every inbound WS message to get consistent tracing.
 *
 * Required span attributes (set automatically or by caller):
 *   - match.id
 *   - player.id
 *   - action.type
 *
 * See docs/OBSERVABILITY.md for the full attribute contract.
 */
export function traceWsMessage<T>(
  messageType: string,
  attributes: Record<string, string>,
  handler: (span: Span) => Promise<T> | T,
): Promise<T> {
  return withActiveSpan(
    `ws.${messageType}`,
    {
      attributes: {
        [ATTR_HTTP_ROUTE]: '/ws',
        [ATTR_NETWORK_PROTOCOL_NAME]: 'websocket',
        ...attributes,
      },
      kind: SpanKind.SERVER,
    },
    handler,
  );
}

/**
 * Creates a named span for an HTTP handler. HTTP instrumentation auto-creates
 * spans for requests, but use this for custom sub-spans inside handlers.
 */
export function traceHttpHandler<T>(
  operationName: string,
  options: HttpTraceOptions,
  handler: (span: Span) => Promise<T> | T,
): Promise<T>;
export function traceHttpHandler<T>(
  operationName: string,
  attributes: Attributes,
  handler: (span: Span) => Promise<T> | T,
): Promise<T>;
export function traceHttpHandler<T>(
  operationName: string,
  handler: (span: Span) => Promise<T> | T,
): Promise<T>;
export function traceHttpHandler<T>(
  operationName: string,
  attributesOrHandler: Attributes | HttpTraceOptions | ((span: Span) => Promise<T> | T),
  maybeHandler?: (span: Span) => Promise<T> | T,
): Promise<T> {
  const options =
    typeof attributesOrHandler === 'function'
      ? {}
      : isHttpTraceOptions(attributesOrHandler)
        ? attributesOrHandler
        : { attributes: attributesOrHandler };
  const handler =
    typeof attributesOrHandler === 'function'
      ? attributesOrHandler
      : (maybeHandler as (span: Span) => Promise<T> | T);

  return withActiveSpan(
    `http.${operationName}`,
    { attributes: options.attributes ?? {}, kind: SpanKind.SERVER },
    async (span) => {
      try {
        return await handler(span);
      } finally {
        const statusCode = options.getStatusCode?.();
        if (statusCode !== undefined) {
          span.setAttribute(ATTR_HTTP_RESPONSE_STATUS_CODE, statusCode);
        }
      }
    },
  );
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { MatchManager, buildMatchEventLog } from '../src/match.js';
import { MatchRepository } from '../src/db/match-repo.js';
import type { WebSocket } from 'ws';
import { computeStateHash } from '@phalanxduel/shared/hash';

function mockSocket(): WebSocket {
  return {
    send: vi.fn(),
    readyState: 1,
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    on: vi.fn(),
    close: vi.fn(),
  } as unknown as WebSocket;
}

const BOT_OPTIONS = {
  botOptions: {
    opponent: 'bot-random' as const,
    botConfig: { strategy: 'random' as const, seed: 42 },
  },
};

describe('event log persistence', () => {
  let manager: MatchManager;

  beforeEach(() => {
    manager = new MatchManager();
  });

  describe('MatchRepository — no-DB guard paths', () => {
    it('saveEventLog is a no-op when no database is configured', async () => {
      const repo = new MatchRepository();
      const log = {
        matchId: '00000000-0000-0000-0000-000000000001',
        events: [],
        fingerprint: 'abc123',
        generatedAt: new Date().toISOString(),
      };
      // Should not throw with no DATABASE_URL
      await expect(repo.saveEventLog(log.matchId, log)).resolves.toBeUndefined();
    });

    it('getEventLog returns null when no database is configured', async () => {
      const repo = new MatchRepository();
      const result = await repo.getEventLog('00000000-0000-0000-0000-000000000001');
      expect(result).toBeNull();
    });
  });

  describe('buildMatchEventLog — fingerprint integrity', () => {
    it('fingerprint is a 64-char SHA-256 hex string', async () => {
      const ws1 = mockSocket();
      const ws2 = mockSocket();
      const { matchId } = manager.createMatch('Alice', ws1);
      await manager.joinMatch(matchId, 'Bob', ws2);

      const match = manager.getMatchSync(matchId)!;
      const log = buildMatchEventLog(match);

      expect(log.fingerprint).toMatch(/^[0-9a-f]{64}$/);
    });

    it('fingerprint matches independent re-computation from events array', async () => {
      const ws1 = mockSocket();
      const ws2 = mockSocket();
      const { matchId } = manager.createMatch('Alice', ws1);
      await manager.joinMatch(matchId, 'Bob', ws2);

      const match = manager.getMatchSync(matchId)!;
      const log = buildMatchEventLog(match);

      expect(computeStateHash(log.events)).toBe(log.fingerprint);
    });

    it('fingerprint changes after a new action is applied', async () => {
      const ws1 = mockSocket();
      const ws2 = mockSocket();
      const { matchId } = manager.createMatch('Alice', ws1);
      const { playerId: p2Id } = await manager.joinMatch(matchId, 'Bob', ws2);

      const match = manager.getMatchSync(matchId)!;
      const logBefore = buildMatchEventLog(match);

      const card = match.state!.players[1]!.hand[0]!;
      await manager.handleAction(matchId, p2Id, {
        type: 'deploy',
        playerIndex: 1,
        column: 0,
        cardId: card.id,
        timestamp: new Date().toISOString(),
      });

      const logAfter = buildMatchEventLog(match);
      expect(logAfter.fingerprint).not.toBe(logBefore.fingerprint);
    });

    it('log contains more events after forfeit (game.completed appended)', async () => {
      const ws1 = mockSocket();
      const ws2 = mockSocket();
      const { matchId } = manager.createMatch('Alice', ws1);
      const { playerId: p2Id } = await manager.joinMatch(matchId, 'Bob', ws2);

      const match = manager.getMatchSync(matchId)!;
      const countBefore = buildMatchEventLog(match).events.length;

      await manager.handleAction(matchId, p2Id, {
        type: 'forfeit',
        playerIndex: 1,
        timestamp: new Date().toISOString(),
      });

      const logAfter = buildMatchEventLog(match);
      expect(logAfter.events.length).toBeGreaterThan(countBefore);
    });
  });

  describe('event log for bot match', () => {
    it('bot match event log has lifecycle events + turn events', () => {
      const ws = mockSocket();
      const { matchId } = manager.createMatch('Human', ws, BOT_OPTIONS);
      const match = manager.getMatchSync(matchId)!;

      const log = buildMatchEventLog(match);
      expect(log.matchId).toBe(matchId);
      expect(log.events.length).toBeGreaterThan(0);
      // Lifecycle events: match.created, player.joined×2, game.initialized
      expect(log.events[0]!.name).toBe('match.created');
    });

    it('bot match partial log fingerprint is valid before game ends', () => {
      const ws = mockSocket();
      const { matchId } = manager.createMatch('Human', ws, BOT_OPTIONS);
      const match = manager.getMatchSync(matchId)!;

      const log = buildMatchEventLog(match);
      expect(log.fingerprint).toMatch(/^[0-9a-f]{64}$/);
      expect(computeStateHash(log.events)).toBe(log.fingerprint);
    });
  });

  describe('event log generatedAt', () => {
    it('generatedAt is a valid ISO timestamp', async () => {
      const ws1 = mockSocket();
      const ws2 = mockSocket();
      const { matchId } = manager.createMatch('Alice', ws1);
      await manager.joinMatch(matchId, 'Bob', ws2);

      const match = manager.getMatchSync(matchId)!;
      const log = buildMatchEventLog(match);

      expect(() => new Date(log.generatedAt)).not.toThrow();
      expect(new Date(log.generatedAt).toISOString()).toBe(log.generatedAt);
    });
  });
});

import { describe, it, expect } from 'vitest';
import { filterStateForPlayer } from '../src/match';
import { createInitialState, drawCards } from '@phalanxduel/engine';
import type { GameState, PartialCard } from '@phalanxduel/shared';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function buildStateWithCards(hand0Count: number, hand1Count: number): GameState {
  const config = {
    matchId: 'test-match-id',
    players: [
      { id: '00000000-0000-0000-0000-000000000001', name: 'Alice' },
      { id: '00000000-0000-0000-0000-000000000002', name: 'Bob' },
    ] as [{ id: string; name: string }, { id: string; name: string }],
    rngSeed: 42,
  };
  let state = createInitialState(config);

  // createInitialState performs automatic 12-card draws.
  // We need to override this for specific test counts.
  for (let i = 0; i < 2; i++) {
    const p = state.players[i]!;
    // Move all hand cards back to drawpile
    p.drawpile = [...p.hand.map((c) => ({ ...c, id: undefined })), ...p.drawpile] as PartialCard[];
    p.hand = [];
  }

  const ts = new Date().toISOString();
  if (hand0Count > 0) state = drawCards(state, 0, hand0Count, ts);
  if (hand1Count > 0) state = drawCards(state, 1, hand1Count, ts);
  return state;
}

// ---------------------------------------------------------------------------
// filterStateForPlayer
// ---------------------------------------------------------------------------

describe('filterStateForPlayer', () => {
  describe('given playerIndex 0 is the viewing player', () => {
    it("should preserve own player's hand unchanged", () => {
      // Arrange
      const state = buildStateWithCards(5, 4);
      const originalHand = [...state.players[0]!.hand];

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect(filtered.players[0]!.hand).toEqual(originalHand);
    });

    it("should preserve own player's drawpile unchanged", () => {
      // Arrange
      const state = buildStateWithCards(5, 4);
      const originalDraw = [...state.players[0]!.drawpile];

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect(filtered.players[0]!.drawpile).toEqual(originalDraw);
    });

    it('should NOT set handCount on own player state', () => {
      // Arrange
      const state = buildStateWithCards(5, 4);

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert — own player should not have handCount injected
      expect((filtered.players[0] as Record<string, unknown>).handCount).toBeUndefined();
    });

    it('should NOT set drawpileCount on own player state', () => {
      // Arrange
      const state = buildStateWithCards(5, 4);

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect((filtered.players[0] as Record<string, unknown>).drawpileCount).toBeUndefined();
    });

    it("should redact opponent's hand to an empty array", () => {
      // Arrange
      const state = buildStateWithCards(5, 4);
      expect(state.players[1]!.hand.length).toBeGreaterThan(0);

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect(filtered.players[1]!.hand).toEqual([]);
    });

    it("should redact opponent's drawpile to an empty array", () => {
      // Arrange
      const state = buildStateWithCards(5, 4);
      expect(state.players[1]!.drawpile.length).toBeGreaterThan(0);

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect(filtered.players[1]!.drawpile).toEqual([]);
    });

    it('should set opponent handCount equal to the original hand length', () => {
      // Arrange
      const state = buildStateWithCards(5, 4);
      const originalOpponentHandLen = state.players[1]!.hand.length;

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect(filtered.players[1]!.handCount).toBe(originalOpponentHandLen);
    });

    it('should set opponent drawpileCount equal to the original drawpile length', () => {
      // Arrange
      const state = buildStateWithCards(5, 4);
      const originalOpponentDrawLen = state.players[1]!.drawpile.length;

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect(filtered.players[1]!.drawpileCount).toBe(originalOpponentDrawLen);
    });
  });

  describe('given playerIndex 1 is the viewing player', () => {
    it("should preserve player 1's own hand unchanged", () => {
      // Arrange
      const state = buildStateWithCards(3, 6);
      const originalHand = [...state.players[1]!.hand];

      // Act
      const filtered = filterStateForPlayer(state, 1);

      // Assert
      expect(filtered.players[1]!.hand).toEqual(originalHand);
    });

    it("should redact player 0's hand to an empty array", () => {
      // Arrange
      const state = buildStateWithCards(3, 6);
      expect(state.players[0]!.hand.length).toBeGreaterThan(0);

      // Act
      const filtered = filterStateForPlayer(state, 1);

      // Assert
      expect(filtered.players[0]!.hand).toEqual([]);
    });

    it("should set player 0's handCount correctly when viewed from player 1", () => {
      // Arrange
      const state = buildStateWithCards(3, 6);
      const originalLen = state.players[0]!.hand.length;

      // Act
      const filtered = filterStateForPlayer(state, 1);

      // Assert
      expect(filtered.players[0]!.handCount).toBe(originalLen);
    });

    it("should set player 0's drawpileCount correctly when viewed from player 1", () => {
      // Arrange
      const state = buildStateWithCards(3, 6);
      const originalLen = state.players[0]!.drawpile.length;

      // Act
      const filtered = filterStateForPlayer(state, 1);

      // Assert
      expect(filtered.players[0]!.drawpileCount).toBe(originalLen);
    });
  });

  describe('given the opponent has an empty hand', () => {
    it('should set handCount to 0 when opponent hand is empty', () => {
      // Arrange — draw only for player 0; player 1 starts with no hand cards
      const state = buildStateWithCards(5, 0);
      expect(state.players[1]!.hand).toEqual([]);

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect(filtered.players[1]!.handCount).toBe(0);
    });

    it('should still correctly report drawpileCount when opponent hand is empty', () => {
      // Arrange
      const state = buildStateWithCards(5, 0);
      const drawLen = state.players[1]!.drawpile.length;

      // Act
      const filtered = filterStateForPlayer(state, 0);

      // Assert
      expect(filtered.players[1]!.drawpileCount).toBe(drawLen);
    });
  });

  describe('given other state fields', () => {
    it('should pass through phase unchanged', () => {
      const state = buildStateWithCards(4, 4);
      expect(filterStateForPlayer(state, 0).phase).toBe(state.phase);
    });

    it('should pass through turnNumber unchanged', () => {
      const state = buildStateWithCards(4, 4);
      expect(filterStateForPlayer(state, 0).turnNumber).toBe(state.turnNumber);
    });

    it('should pass through activePlayerIndex unchanged', () => {
      const state = buildStateWithCards(4, 4);
      expect(filterStateForPlayer(state, 0).activePlayerIndex).toBe(state.activePlayerIndex);
    });

    it('should pass through rngSeed unchanged', () => {
      const state = buildStateWithCards(4, 4);
      expect(filterStateForPlayer(state, 0).rngSeed).toBe(state.rngSeed);
    });

    it("should pass through opponent's discardPile unchanged (discard is public info)", () => {
      const state = buildStateWithCards(4, 4);
      expect(filterStateForPlayer(state, 0).players[1]!.discardPile).toEqual(
        state.players[1]!.discardPile,
      );
    });

    it("should pass through opponent's lifepoints unchanged", () => {
      const state = buildStateWithCards(4, 4);
      expect(filterStateForPlayer(state, 0).players[1]!.lifepoints).toBe(
        state.players[1]!.lifepoints,
      );
    });

    it("should pass through opponent's battlefield unchanged", () => {
      const state = buildStateWithCards(4, 4);
      expect(filterStateForPlayer(state, 0).players[1]!.battlefield).toEqual(
        state.players[1]!.battlefield,
      );
    });
  });

  describe('given immutability', () => {
    it('should not mutate the original state hand arrays', () => {
      // Arrange
      const state = buildStateWithCards(5, 4);
      const originalHand1 = state.players[1]!.hand;

      // Act
      filterStateForPlayer(state, 0);

      // Assert — original state is untouched
      expect(state.players[1]!.hand).toBe(originalHand1);
      expect(state.players[1]!.hand.length).toBeGreaterThan(0);
    });

    it('should not mutate the original state drawpile arrays', () => {
      // Arrange
      const state = buildStateWithCards(5, 4);
      const originalDraw1 = state.players[1]!.drawpile;

      // Act
      filterStateForPlayer(state, 0);

      // Assert
      expect(state.players[1]!.drawpile).toBe(originalDraw1);
    });
  });
});

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import supertest from 'supertest';
import { buildApp } from '../src/app';

describe('Health Endpoints', () => {
  let app: Awaited<ReturnType<typeof buildApp>>;
  let request: ReturnType<typeof supertest>;

  beforeAll(async () => {
    app = await buildApp();
    await app.ready();
    request = supertest(app.server);
  });

  afterAll(async () => {
    await app.close();
  });

  describe('GET /health', () => {
    describe('given the server is running', () => {
      it('should return 200 with status ok', async () => {
        const response = await request.get('/health');

