import { describe, it, expect, beforeEach, vi } from 'vitest';
import { MatchManager } from '../src/match.js';
import type { WebSocket } from 'ws';
import type { ServerMessage } from '@phalanxduel/shared';
import { PhalanxEventSchema } from '@phalanxduel/shared';

function mockSocket() {
  const messages: ServerMessage[] = [];
  return {
    send: vi.fn((data: string) => messages.push(JSON.parse(data))),
    readyState: 1,
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    on: vi.fn(),
    close: vi.fn(),
    _messages: messages,
  } as unknown as WebSocket & { _messages: ServerMessage[] };
}

function lastMessage(
  socket: WebSocket & { _messages: ServerMessage[] },
): ServerMessage | undefined {
  return socket._messages[socket._messages.length - 1];
}

describe('MatchManager', () => {
  let manager: MatchManager;

  beforeEach(() => {
    manager = new MatchManager();
  });

  describe('createMatch', () => {
    it('should return valid UUIDs and player index 0', () => {
      const socket = mockSocket();
      const result = manager.createMatch('Player 1', socket);

      expect(result.matchId).toMatch(/^[0-9a-f-]{36}$/);
      expect(result.playerId).toMatch(/^[0-9a-f-]{36}$/);
      expect(result.playerIndex).toBe(0);
    });
  });

  describe('joinMatch', () => {
    it('should broadcast gameState to both players after join', async () => {
      const socket1 = mockSocket();
      const socket2 = mockSocket();

      const { matchId } = manager.createMatch('Player 1', socket1);
      await manager.joinMatch(matchId, 'Player 2', socket2);
      manager.broadcastMatchState(matchId);
      // broadcastMatchState uses async IIFE; flush microtasks
      await vi.waitFor(() => { expect(lastMessage(socket1)?.type).toBe('gameState'); });

      const msg1 = lastMessage(socket1);
      const msg2 = lastMessage(socket2);
      expect(msg1?.type).toBe('gameState');
      expect(msg2?.type).toBe('gameState');
    });

    it('should initialize game in DeploymentPhase with 12 cards per hand', async () => {
      const socket1 = mockSocket();
      const socket2 = mockSocket();

      const { matchId } = manager.createMatch('Player 1', socket1);
      await manager.joinMatch(matchId, 'Player 2', socket2);
      manager.broadcastMatchState(matchId);
      await vi.waitFor(() => { expect(lastMessage(socket1)?.type).toBe('gameState'); });

      const msg = lastMessage(socket1) as Extract<ServerMessage, { type: 'gameState' }>;
      expect(msg.type).toBe('gameState');
      // Game starts in DeploymentPhase (modeClassicDeployment: true by default)
      expect(msg.result.postState.phase).toBe('DeploymentPhase');
      expect(msg.result.postState.players[0]!.hand.length).toBe(12);
    });
  });

  describe('handleAction', () => {
    it('should accept a valid deploy action and broadcast updated state', async () => {
      const socket1 = mockSocket();
      const socket2 = mockSocket();

      const { matchId } = manager.createMatch('Player 1', socket1);
      const { playerId: p2Id } = await manager.joinMatch(matchId, 'Player 2', socket2);
      manager.broadcastMatchState(matchId);
      await vi.waitFor(() => { expect(lastMessage(socket2)?.type).toBe('gameState'); });

      // Use socket2 (player 1) as the actor; socket1 sees player 1's action broadcast
      const initialMsg = lastMessage(socket2) as Extract<ServerMessage, { type: 'gameState' }>;
      const cardId = initialMsg.result.postState.players[1]!.hand[0]!.id;

      await manager.handleAction(matchId, p2Id, {
        type: 'deploy',
        playerIndex: 1,
        column: 0,
        cardId,
        timestamp: new Date().toISOString(),
      });

      const updatedMsg = lastMessage(socket1) as Extract<ServerMessage, { type: 'gameState' }>;
      expect(updatedMsg.result.action.type).toBe('deploy');
      expect(updatedMsg.result.postState.players[1]!.handCount).toBe(11);
    });

    it('should populate turnHash on the last transactionLog entry after a deploy action', async () => {
      const socket1 = mockSocket();
      const socket2 = mockSocket();

      const { matchId } = manager.createMatch('Player 1', socket1);
      const { playerId: p2Id } = await manager.joinMatch(matchId, 'Player 2', socket2);
      manager.broadcastMatchState(matchId);
      await vi.waitFor(() => { expect(lastMessage(socket2)?.type).toBe('gameState'); });

      const initialMsg = lastMessage(socket2) as Extract<ServerMessage, { type: 'gameState' }>;
      const cardId = initialMsg.result.postState.players[1]!.hand[0]!.id;

      await manager.handleAction(matchId, p2Id, {
        type: 'deploy',
        playerIndex: 1,
        column: 0,
        cardId,
        timestamp: new Date().toISOString(),
      });

      const updatedMsg = lastMessage(socket1) as Extract<ServerMessage, { type: 'gameState' }>;
      const lastEntry = updatedMsg.result.postState.transactionLog?.at(-1);
      expect(lastEntry).toBeDefined();
      expect(typeof lastEntry?.turnHash).toBe('string');
      expect(lastEntry?.turnHash).toMatch(/^[0-9a-f]{64}$/);
    });

    it('should broadcast non-empty events array after a deploy action', async () => {
      const socket1 = mockSocket();
      const socket2 = mockSocket();

      const { matchId } = manager.createMatch('Player 1', socket1);
      const { playerId: p2Id } = await manager.joinMatch(matchId, 'Player 2', socket2);
      manager.broadcastMatchState(matchId);
      await vi.waitFor(() => { expect(lastMessage(socket2)?.type).toBe('gameState'); });

      const initialMsg = lastMessage(socket2) as Extract<ServerMessage, { type: 'gameState' }>;
      const cardId = initialMsg.result.postState.players[1]!.hand[0]!.id;

      await manager.handleAction(matchId, p2Id, {
        type: 'deploy',
        playerIndex: 1,
        column: 0,
        cardId,
        timestamp: new Date().toISOString(),
      });

      const updatedMsg = lastMessage(socket1) as Extract<ServerMessage, { type: 'gameState' }>;
      expect(updatedMsg.result.events).toBeDefined();
      expect(updatedMsg.result.events!.length).toBeGreaterThan(0);
      for (const event of updatedMsg.result.events!) {
        expect(PhalanxEventSchema.safeParse(event).success).toBe(true);
      }
    });
  });

  describe('cleanupMatches', () => {
    it('should remove gameOver matches after TTL', async () => {
      const socket1 = mockSocket();
      const socket2 = mockSocket();

      const { matchId } = manager.createMatch('Player 1', socket1);
      await manager.joinMatch(matchId, 'Player 2', socket2);

      const match = await manager.getMatch(matchId);
      // Force game over
      match!.state!.phase = 'gameOver';
      match!.lastActivityAt = Date.now() - 10 * 60 * 1000; // 10 mins ago

      const removed = manager.cleanupMatches();
      expect(removed).toBe(1);
      expect(await manager.getMatch(matchId)).toBeNull();
    });
  });
});

/**
 * Integration test: verifies that OTel-native spans and metrics actually record
 * through the real SDK pipeline (in-memory exporters, no network).
 *
 * Unlike the unit tests that mock the OTel API, this boots real providers
 * to catch misconfigured registrations and silent no-op failures.
 */
import { afterAll, beforeAll, describe, expect, it } from 'vitest';
import { SpanKind, metrics } from '@opentelemetry/api';
import {
  InMemorySpanExporter,
  SimpleSpanProcessor,
  NodeTracerProvider,
} from '@opentelemetry/sdk-trace-node';
import {
  InMemoryMetricExporter,
  MeterProvider,
  PeriodicExportingMetricReader,
  AggregationTemporality,
} from '@opentelemetry/sdk-metrics';

let spanExporter: InMemorySpanExporter;
let metricExporter: InMemoryMetricExporter;
let tracerProvider: NodeTracerProvider;
let meterProvider: MeterProvider;
let metricReader: PeriodicExportingMetricReader;

beforeAll(() => {
  spanExporter = new InMemorySpanExporter();
  tracerProvider = new NodeTracerProvider({
    spanProcessors: [new SimpleSpanProcessor(spanExporter)],
  });
  tracerProvider.register();

  metricExporter = new InMemoryMetricExporter(AggregationTemporality.CUMULATIVE);
  metricReader = new PeriodicExportingMetricReader({
    exporter: metricExporter,
    exportIntervalMillis: 100,
  });
  meterProvider = new MeterProvider({
    readers: [metricReader],
  });
  metrics.setGlobalMeterProvider(meterProvider);
});

afterAll(async () => {
  await tracerProvider.shutdown();
  await meterProvider.shutdown();
});

describe('OTel integration: spans', () => {
  it('withActiveSpan records a span with attributes through the real SDK', async () => {
    // Dynamic import AFTER providers are registered so observability.ts
    // picks up the real tracer/meter.
    const { withActiveSpan } = await import('../src/observability.js');

    const result = await withActiveSpan(
      'test.integration',
      { attributes: { 'test.key': 'test-value' } },
      (span) => {
        span.setAttribute('extra', 42);
        return 'hello';
      },
    );

    expect(result).toBe('hello');

    const spans = spanExporter.getFinishedSpans();
    const testSpan = spans.find((s) => s.name === 'test.integration');
    expect(testSpan).toBeDefined();
    expect(testSpan!.attributes['test.key']).toBe('test-value');
    expect(testSpan!.attributes.extra).toBe(42);
    expect(testSpan!.status.code).toBe(0); // UNSET = success
  });

  it('withActiveSpan records error status on the real span', async () => {
    const { withActiveSpan } = await import('../src/observability.js');

    await expect(
      withActiveSpan('test.error', {}, async () => {
        throw new Error('integration-boom');
      }),
    ).rejects.toThrow('integration-boom');

    const spans = spanExporter.getFinishedSpans();
    const errorSpan = spans.find((s) => s.name === 'test.error');
    expect(errorSpan).toBeDefined();
    expect(errorSpan!.status.code).toBe(2); // ERROR
    expect(errorSpan!.status.message).toBe('integration-boom');
    expect(errorSpan!.events.length).toBeGreaterThan(0); // recordException creates an event
  });

  it('traceWsMessage creates a ws-prefixed span through the real SDK', async () => {
    const { traceWsMessage } = await import('../src/tracing.js');

    const result = await traceWsMessage(
      'joinMatch',
      { 'match.id': 'match-integration' },
      (span) => {
        span.setAttribute('player.id', 'p-1');
        return { joined: true };
      },
    );

    expect(result).toEqual({ joined: true });

    const spans = spanExporter.getFinishedSpans();
    const wsSpan = spans.find((s) => s.name === 'ws.joinMatch');
    expect(wsSpan).toBeDefined();
    expect(wsSpan!.attributes['match.id']).toBe('match-integration');
    expect(wsSpan!.attributes['player.id']).toBe('p-1');
    expect(wsSpan!.attributes['network.protocol.name']).toBe('websocket');
    expect(wsSpan!.kind).toBe(SpanKind.SERVER);
  });

  it('traceHttpHandler creates an http-prefixed span through the real SDK', async () => {
    const { traceHttpHandler } = await import('../src/tracing.js');

    const result = await traceHttpHandler('createMatch', (span) => {
      span.setAttribute('match.id', 'm-http');
      return { matchId: 'm-http' };
    });

    expect(result).toEqual({ matchId: 'm-http' });

    const spans = spanExporter.getFinishedSpans();
    const httpSpan = spans.find((s) => s.name === 'http.createMatch');
    expect(httpSpan).toBeDefined();
    expect(httpSpan!.attributes['match.id']).toBe('m-http');
    expect(httpSpan!.kind).toBe(SpanKind.SERVER);
  });
});

