import { describe, it, expect, beforeEach, vi } from 'vitest';
import { MatchManager } from '../src/match.js';
import type { ServerMessage, GameState } from '@phalanxduel/shared';
import type { WebSocket } from 'ws';

function mockSocket(): WebSocket {
  return {
    send: vi.fn(),
    readyState: 1,
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    on: vi.fn(),
    close: vi.fn(),
  } as unknown as WebSocket;
}

function parseSentMessages(socket: WebSocket): ServerMessage[] {
  return (socket.send as ReturnType<typeof vi.fn>).mock.calls.map(
    ([raw]: [string]) => JSON.parse(raw) as ServerMessage,
  );
}

describe('preState broadcast correctness', () => {
  let manager: MatchManager;

  beforeEach(() => {
    manager = new MatchManager();
  });

  it('preState reflects the state BEFORE the action was applied', async () => {
    const ws1 = mockSocket();
    const ws2 = mockSocket();

    const { matchId } = manager.createMatch('Alice', ws1);
    await manager.joinMatch(matchId, 'Bob', ws2);

    // Snapshot hand sizes before the action
    const match = await manager.getMatch(matchId);
    const handSizeBefore = match!.state!.players[1]!.hand.length;
    const battlefieldBefore = match!.state!.players[1]!.battlefield.filter(
      (c) => c !== null,
    ).length;

    // Clear mocks to isolate action broadcast
    (ws1.send as ReturnType<typeof vi.fn>).mockClear();
    (ws2.send as ReturnType<typeof vi.fn>).mockClear();

    // P2 (Bob, playerIndex 1) deploys first per initiative rules
    const cardId = match!.state!.players[1]!.hand[0]!.id;
    const p2 = match!.players[1]!;
    await manager.handleAction(matchId, p2.playerId, {
      type: 'deploy',
      playerIndex: 1,
      column: 0,
      cardId,
      timestamp: new Date().toISOString(),
    });

    // Check Bob's (ws2) broadcast — his own state is unredacted in postState
    const bobMessages = parseSentMessages(ws2);
    const gameStateMsg = bobMessages.find(
      (m): m is Extract<ServerMessage, { type: 'gameState' }> => m.type === 'gameState',
    );
    expect(gameStateMsg).toBeDefined();

    const preState = gameStateMsg!.result.preState as GameState;
    const postState = gameStateMsg!.result.postState as GameState;

    // postState should show the deploy: one fewer card in hand, one more on battlefield
    const postHandSize = postState.players[1]!.hand.length;
    const postBattlefield = postState.players[1]!.battlefield.filter((c) => c !== null).length;
    expect(postHandSize).toBe(handSizeBefore - 1);
    expect(postBattlefield).toBe(battlefieldBefore + 1);

    // THE KEY ASSERTION: preState must reflect the state BEFORE the deploy.
    // Bug: broadcastState sends match.state (post-action) as preState, so
    // preState.players[1].hand.length === handSizeBefore - 1 (wrong).
    // Fix: preState.players[1].hand.length === handSizeBefore (correct).
    const preHandSize = preState.players[1]!.hand.length;
    expect(preHandSize).toBe(handSizeBefore);
  });
});

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { buildApp } from '../src/app';
import type { ServerMessage } from '@phalanxduel/shared';
import WebSocket from 'ws';

async function sendAndWait(ws: WebSocket, msg: unknown): Promise<unknown> {
  return new Promise((resolve, reject) => {
    const onMessage = (data: WebSocket.Data) => {
      ws.off('message', onMessage);
      resolve(JSON.parse(data.toString()));
    };
    ws.on('message', onMessage);
    ws.send(JSON.stringify(msg), (err) => {
      if (err) reject(err);
    });

    setTimeout(() => {
      ws.off('message', onMessage);
      reject(new Error('Timed out waiting for response'));
    }, 5000);
  });
}

function waitForMessageType<T>(ws: WebSocket, type: string): Promise<T> {
  return new Promise((resolve, reject) => {
    const onMessage = (data: WebSocket.Data) => {
      const parsed = JSON.parse(data.toString());
      if (parsed.type === type) {
        ws.off('message', onMessage);
        resolve(parsed);
      }
    };
    ws.on('message', onMessage);

    setTimeout(() => {
      ws.off('message', onMessage);
      reject(new Error(`Timed out waiting for message type ${type}`));
    }, 5000);
  });
}

async function connect(url: string, options: { origin?: string } = {}): Promise<WebSocket> {
  const ws = new WebSocket(url, {
    headers: {
      origin: options.origin || 'http://localhost:3001',
    },
  });
  await new Promise((resolve, reject) => {
    ws.on('open', resolve);
    ws.on('error', reject);
  });
  return ws;
}

describe('WebSocket integration', () => {
  let app: Awaited<ReturnType<typeof buildApp>>;
  let url: string;

  beforeAll(async () => {
    app = await buildApp();
    await app.listen({ port: 0, host: '127.0.0.1' });
    const address = app.server.address() as { port: number };
    url = `ws://127.0.0.1:${address.port}/ws`;
  });

  afterAll(async () => {
    if (app) await app.close();
  });

  it('should reject connection with invalid origin', async () => {
    const ws = new WebSocket(url, {
      headers: { origin: 'http://malicious.com' },
    });
    const closePromise = new Promise<{ code: number; reason: string }>((resolve) => {
      ws.on('close', (code, reason) => { resolve({ code, reason: reason.toString() }); });
    });
    const result = await closePromise;
    expect(result.code).toBe(1008);
    expect(result.reason).toBe('Invalid Origin');
  });

  it('should create a match and return matchId', async () => {
    const ws = await connect(url);

    const response = (await sendAndWait(ws, {
      type: 'createMatch',
      playerName: 'Alice',
    })) as { type: string; matchId: string };

    expect(response.type).toBe('matchCreated');
    expect(response.matchId).toBeTruthy();

    ws.close();
  });

  it('should receive matchError for invalid JSON', async () => {
    const ws = await connect(url);

    const responsePromise = new Promise((resolve) => {
      ws.on('message', (data) => { resolve(JSON.parse(data.toString())); });
    });

    ws.send('invalid json');
    const response = (await responsePromise) as { type: string; code: string };
    expect(response.type).toBe('matchError');
    expect(response.code).toBe('PARSE_ERROR');

    ws.close();
  });

  it('should allow deploy action in DeploymentPhase', async () => {
    const ws1 = await connect(url);
    const ws2 = await connect(url);

    const created = (await sendAndWait(ws1, {
      type: 'createMatch',
      playerName: 'Alice',
    })) as { matchId: string };
    const matchId = created.matchId;

    // Set up gameState listener BEFORE joining to avoid race condition
    const gameStatePromise = waitForMessageType<Extract<ServerMessage, { type: 'gameState' }>>(
      ws2,
      'gameState',
    );
    await sendAndWait(ws2, { type: 'joinMatch', matchId, playerName: 'Bob' });
    const initialMsg = await gameStatePromise;
    const cardId = initialMsg.result.postState.players[1]!.hand[0]!.id;

    const deployResult = (await sendAndWait(ws2, {
      type: 'action',
      matchId,
      action: {
        type: 'deploy',
        playerIndex: 1,
        column: 0,
        cardId,
        timestamp: new Date().toISOString(),
      },
    })) as Extract<ServerMessage, { type: 'gameState' }>;

    expect(deployResult.type).toBe('gameState');
    expect(deployResult.result.action.type).toBe('deploy');

    ws1.close();
    ws2.close();
  });

  it('should initialize game state with createMatch matchParams from websocket', async () => {
    const ws1 = await connect(url);
    const ws2 = await connect(url);

    const created = (await sendAndWait(ws1, {
      type: 'createMatch',
      playerName: 'Alice',
      matchParams: { rows: 1, columns: 2 },
    })) as { matchId: string };
    const matchId = created.matchId;

    // Set up gameState listener BEFORE joining to avoid race condition
    const gameStatePromise = waitForMessageType<Extract<ServerMessage, { type: 'gameState' }>>(
      ws1,
      'gameState',
    );
    await sendAndWait(ws2, { type: 'joinMatch', matchId, playerName: 'Bob' });
    const msg = await gameStatePromise;
    expect(msg.result.postState.params.rows).toBe(1);
    expect(msg.result.postState.params.columns).toBe(2);

    ws1.close();
    ws2.close();
  });

  it('should allow two WS joins on a REST-created match and start the game', async () => {
    const res = await app.inject({
      method: 'POST',
      url: '/matches',
    });
    const matchId = res.json().matchId;

    const ws1 = await connect(url);
    const ws2 = await connect(url);

    await sendAndWait(ws1, {
      type: 'joinMatch',
      matchId,
      playerName: 'Alice',
    });

    const ws1GameStatePromise = waitForMessageType<{ type: 'gameState'; matchId: string }>(
      ws1,
      'gameState',
    );
    const ws2GameStatePromise = waitForMessageType<{
      type: 'gameState';
      matchId: string;
      result: { postState: { phase: string } };
    }>(ws2, 'gameState');

    ws2.send(
      JSON.stringify({
        type: 'joinMatch',
        matchId,
        playerName: 'Bob',
      }),
    );

    const secondJoin = await waitForMessageType<Extract<ServerMessage, { type: 'matchJoined' }>>(
      ws2,
      'matchJoined',
    );
    expect(secondJoin.type).toBe('matchJoined');
    expect(secondJoin.playerIndex).toBe(1);

    const [ws1GameState, ws2GameState] = await Promise.all([
      ws1GameStatePromise,
      ws2GameStatePromise,
    ]);
    expect(ws1GameState.matchId).toBe(matchId);
    expect(ws2GameState.matchId).toBe(matchId);
    expect(['DeploymentPhase', 'AttackPhase']).toContain(ws2GameState.result.postState.phase);

    ws1.close();
    ws2.close();
  });

  it('should respond to authenticate with auth_error for invalid token', async () => {
    const ws = await connect(url);

    const response = (await sendAndWait(ws, {
      type: 'authenticate',
      token: 'invalid-jwt-token',
    })) as { type: string; error: string };

    expect(response.type).toBe('auth_error');
    expect(response.error).toBe('Invalid token');

    ws.close();
  });
});

import { z } from 'zod';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { fileURLToPath } from 'node:url';

const SCRIPT_DIR = path.dirname(fileURLToPath(import.meta.url));
const SHARED_ROOT = path.resolve(SCRIPT_DIR, '..');
const TYPES_PATH = path.join(SHARED_ROOT, 'src', 'types.ts');
const SCHEMAS_DIR = path.join(SHARED_ROOT, 'schemas');

/**
 * Public event envelopes — the schemas external consumers validate against.
 * Maps Zod export name → kebab-case output filename (without .schema.json).
 *
 * Internal types (Card, BattlefieldCard, PlayerState, etc.) are inlined
 * automatically — no separate files needed.
 */
const PUBLIC_SCHEMAS: Record<string, string> = {
  ServerMessageSchema: 'server-messages',
  ClientMessageSchema: 'client-messages',
  PhalanxTurnResultSchema: 'turn-result',
  GameStateSchema: 'game-state',
  PhalanxEventSchema: 'event',
  MatchEventLogSchema: 'match-event-log',
};

async function main(): Promise<void> {
  const schemas = await import('../src/schema');

  // Collect ALL exports ending with "Schema" that are Zod types (for types.ts)
  const allSchemaEntries: [string, z.ZodTypeAny][] = [];
  for (const [key, value] of Object.entries(schemas)) {
    if (key.endsWith('Schema') && value instanceof z.ZodType) {
      allSchemaEntries.push([key, value]);
    }
  }

  if (allSchemaEntries.length === 0) {
    console.error('No Zod schemas found in shared/src/schema.ts');
    process.exit(1);
  }

  // --- Generate types.ts (all schemas) ---
  const lines: string[] = [
    '// AUTO-GENERATED — DO NOT EDIT',
    '// Source: shared/src/schema.ts',
    '// Regenerate: pnpm schema:gen',
    '',
    "import type { z } from 'zod';",
    'import type {',
    ...allSchemaEntries.map(([name]) => `  ${name},`),
    "} from './schema';",
    '',
    ...allSchemaEntries.map(([name]) => {
      const typeName = name.replace(/Schema$/, '');
      return `export type ${typeName} = z.infer<typeof ${name}>;`;
    }),
    '', // trailing newline
  ];

  fs.writeFileSync(TYPES_PATH, lines.join('\n'));
  console.log(`Generated ${path.relative(process.cwd(), TYPES_PATH)}`);

  // --- Generate public JSON Schema files ---
  fs.mkdirSync(SCHEMAS_DIR, { recursive: true });

  // Remove stale schema files that are no longer in PUBLIC_SCHEMAS
  const expectedFiles = new Set(Object.values(PUBLIC_SCHEMAS).map((f) => `${f}.schema.json`));
  for (const existing of fs.readdirSync(SCHEMAS_DIR)) {
    if (existing.endsWith('.schema.json') && !expectedFiles.has(existing)) {
      fs.unlinkSync(path.join(SCHEMAS_DIR, existing));
      console.log(`Removed stale ${existing}`);
    }
  }

  const schemaMap = new Map(allSchemaEntries);
  let generated = 0;

  for (const [zodName, fileName] of Object.entries(PUBLIC_SCHEMAS)) {
    const zodSchema = schemaMap.get(zodName);
    if (!zodSchema) {
      console.error(`Public schema '${zodName}' not found in shared/src/schema.ts`);
      process.exit(1);
    }

    const jsonSchema = z.toJSONSchema(zodSchema, { target: 'draft-2020-12' });

    const filePath = path.join(SCHEMAS_DIR, `${fileName}.schema.json`);
    fs.writeFileSync(filePath, JSON.stringify(jsonSchema, null, 2) + '\n');
    console.log(`Generated ${path.relative(process.cwd(), filePath)}`);
    generated++;
  }

  console.log(
    `\nSchema generation complete: ${generated} public schemas, ${allSchemaEntries.length} types.`,
  );
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

