// --- 5. Game DSL & Atomic Payloads ---

/**
 * Phalanx DSL (Section 20.1)
 * Examples: "D:0:cardID", "A:0:3", "P", "R:cardID", "F"
 */
export const ActionDSLSchema = z.string().regex(/^(D:\d+:[\w:]+|A:\d+:\d+|P|R:[\w:]+|F)$/);

/**
 * Standard Action Schema
 */
export const ActionSchema = z.discriminatedUnion('type', [
  z.object({
    type: z.literal('deploy'),
    playerIndex: z.number(),
    column: z.number(),
    cardId: z.string(),
    timestamp: z.string().datetime(),
  }),
  z.object({
    type: z.literal('attack'),
    playerIndex: z.number(),
    attackingColumn: z.number(),
    defendingColumn: z.number(),
    timestamp: z.string().datetime(),
  }),
  z.object({ type: z.literal('pass'), playerIndex: z.number(), timestamp: z.string().datetime() }),
  z.object({
    type: z.literal('reinforce'),
    playerIndex: z.number(),
    cardId: z.string(),
    timestamp: z.string().datetime(),
  }),
  z.object({
    type: z.literal('forfeit'),
    playerIndex: z.number(),
    timestamp: z.string().datetime(),
  }),
  z.object({
    type: z.literal('system:init'),
    timestamp: z.string().datetime(),
  }),
]);

// --- 4. Game State & Duel Format ---

export const PlayerSchema = z.object({
  id: z.string().uuid(),
  name: z.string().trim().min(1).max(50),
});

export const PlayerStateSchema = z.object({
  player: PlayerSchema,
  hand: z.array(CardSchema),
  battlefield: z.array(z.union([BattlefieldCardSchema, z.null()])),
  drawpile: z.array(PartialCardSchema),
  discardPile: z.array(CardSchema),
  lifepoints: z.number().int().min(0),
  deckSeed: z.number().int(),

  // Filtering fields
  handCount: z.number().int().optional(),
  drawpileCount: z.number().int().optional(),
  discardPileCount: z.number().int().optional(),
});

export const CombatBonusTypeSchema = z.enum([
  'aceInvulnerable',
  'aceVsAce',
  'diamondDoubleDefense',
  'diamondDeathShield',
  'clubDoubleOverflow',
  'spadeDoubleLp',
  'heartDeathShield',
  'faceCardIneligible',
]);

export const CombatLogStepSchema = z.object({
  target: z.enum(['frontCard', 'backCard', 'playerLp']),
  card: CardSchema.optional(),
  incomingDamage: z.number().int().min(0).optional(),
  damage: z.number().int().min(0),
  effectiveHp: z.number().int().min(0).optional(),
  hpBefore: z.number().int().min(0).optional(),
  hpAfter: z.number().int().min(0).optional(),
  lpBefore: z.number().int().min(0).optional(),
  lpAfter: z.number().int().min(0).optional(),
  absorbed: z.number().int().min(0).optional(),
  overflow: z.number().int().min(0).optional(),
  destroyed: z.boolean().optional(),
  bonuses: z.array(CombatBonusTypeSchema).optional(),
});

export const CombatLogEntrySchema = z.object({
  turnNumber: z.number().int().min(0),
  attackerPlayerIndex: z.number().int().min(0).max(1),
  attackerCard: CardSchema,
  targetColumn: z.number().int().min(0).max(11),
  baseDamage: z.number().int().min(0),
  totalLpDamage: z.number().int().min(0),
  steps: z.array(CombatLogStepSchema),
});

export const TransactionDetailSchema = z.discriminatedUnion('type', [
  z.object({
    type: z.literal('deploy'),
    gridIndex: z.number().int(),
    phaseAfter: GamePhaseSchema,
  }),
  z.object({
    type: z.literal('attack'),
    combat: CombatLogEntrySchema,
    reinforcementTriggered: z.boolean(),
    victoryTriggered: z.boolean(),
  }),
  z.object({ type: z.literal('pass') }),
  z.object({
    type: z.literal('reinforce'),
    column: z.number().int(),
    gridIndex: z.number().int(),
    cardsDrawn: z.number().int(),
    reinforcementComplete: z.boolean(),
  }),
  z.object({ type: z.literal('forfeit'), winnerIndex: z.number().int() }),
]);

export const PhaseHopTraceSchema = z.object({
  from: GamePhaseSchema,
  trigger: z.string().min(1),
  to: GamePhaseSchema,
});

export const TransactionLogEntrySchema = z.object({
  sequenceNumber: z.number().int().min(0),
  action: ActionSchema,
  stateHashBefore: z.string(),
  stateHashAfter: z.string(),
  timestamp: z.string().datetime(),
  details: TransactionDetailSchema,
  phaseTrace: z.array(PhaseHopTraceSchema).optional(),
  phaseTraceDigest: z.string().optional(),
  turnHash: z.string().optional(),
});

/**
 * Phalanx: Duel Match State
 */
export const GameStateSchema = z.object({
  matchId: z.string().uuid(),
  specVersion: z.literal('1.0'),
  params: MatchParametersSchema,

  players: z.array(PlayerStateSchema).length(2),
  activePlayerIndex: z.number().int().min(0).max(1),
  phase: GamePhaseSchema,
  turnNumber: z.number().int().min(0),

  // Optional Context
  gameOptions: GameOptionsSchema.optional(),
  reinforcement: z
    .object({
      column: z.number().int().min(0).max(11),
      attackerIndex: z.number().int().min(0).max(1),
    })
    .optional(),

  // Pass limit tracking (modePassRules enforcement)
  passState: z
    .object({
      consecutivePasses: z.tuple([z.number().int().min(0), z.number().int().min(0)]),
      totalPasses: z.tuple([z.number().int().min(0), z.number().int().min(0)]),
    })
    .optional(),

  // Replay integrity metadata is stored per transaction entry.
  transactionLog: z.array(TransactionLogEntrySchema).optional(),

  outcome: z
    .object({
      winnerIndex: z.number().int(),
      victoryType: VictoryTypeSchema,
      turnNumber: z.number().int(),
    })
    .nullish(),
});

/**
 * Atomic Turn Payload (Section 20.2)
 * The definitive response for cross-platform play.
 */
export const PhalanxTurnResultSchema = z.object({
  matchId: z.string().uuid(),
  playerId: z.string().uuid(),
  preState: GameStateSchema,
  postState: GameStateSchema,
  action: ActionSchema,
  events: z.array(PhalanxEventSchema).optional(),
  turnHash: z.string().optional(),
  telemetry: z
    .object({
      events: z.array(z.string()).optional(),
      metadata: z.record(z.string(), z.union([z.string(), z.number(), z.boolean()])).optional(),
    })
    .optional(),
});

// --- 6. Match Event Log ---

/**
 * Unified match event log: lifecycle events prepended to all turn-derived events.
 * The fingerprint is SHA-256 of the sorted-key JSON of the events array,
 * allowing offline verification without re-deriving.
 */
export const MatchEventLogSchema = z.object({
  matchId: z.string().uuid(),
  events: z.array(PhalanxEventSchema),
  fingerprint: z.string(),
  generatedAt: z.string().datetime(),
});

// --- WebSocket Protocol Envelopes ---

export const ErrorResponseSchema = z.object({
  error: z.string(),
  code: z.string(),
  details: z.unknown().optional(),
});

export const MatchCreatedMessageSchema = z.object({
  type: z.literal('matchCreated'),
  matchId: z.string().uuid(),
  playerId: z.string().uuid(),
  playerIndex: z.number().int().min(0).max(1),
});

export const GameStateMessageSchema = z.object({
  type: z.literal('gameState'),
  matchId: z.string().uuid(),
  result: PhalanxTurnResultSchema,
  spectatorCount: z.number().int().min(0).optional(),
});

export const ServerMessageSchema = z.discriminatedUnion('type', [
  MatchCreatedMessageSchema,
  GameStateMessageSchema,
  z.object({ type: z.literal('actionError'), error: z.string(), code: z.string() }),
  z.object({ type: z.literal('matchError'), error: z.string(), code: z.string() }),
  z.object({
    type: z.literal('matchJoined'),
    matchId: z.string().uuid(),
    playerId: z.string().uuid(),
    playerIndex: z.number(),
  }),
  z.object({
    type: z.literal('spectatorJoined'),
    matchId: z.string().uuid(),
    spectatorId: z.string().uuid(),
  }),
  z.object({ type: z.literal('opponentDisconnected'), matchId: z.string().uuid() }),
  z.object({ type: z.literal('opponentReconnected'), matchId: z.string().uuid() }),
  z.object({
    type: z.literal('authenticated'),
    user: z.object({
      id: z.string().uuid(),
      name: z.string(),
      gamertag: z.string().optional(),
      suffix: z.number().nullable().optional(),
      elo: z.number(),
    }),
  }),
  z.object({ type: z.literal('auth_error'), error: z.string() }),
]);

export const ClientMessageSchema = z.discriminatedUnion('type', [
  z.object({
    type: z.literal('createMatch'),
    playerName: z.string().trim().min(1).max(50),
    gameOptions: GameOptionsSchema.optional(),
    rngSeed: z.number().optional(),
    opponent: z.enum(['human', 'bot-random', 'bot-heuristic']).optional(),
    matchParams: CreateMatchParamsPartialSchema.optional(),
  }),
  z.object({
    type: z.literal('joinMatch'),
    matchId: z.string().uuid(),
    playerName: z.string().trim().min(1).max(50),
  }),
  z.object({ type: z.literal('watchMatch'), matchId: z.string().uuid() }),
  z.object({ type: z.literal('action'), matchId: z.string().uuid(), action: ActionSchema }),
  z.object({ type: z.literal('authenticate'), token: z.string() }),
]);

import { describe, it, expect } from 'vitest';
import {
  CardSchema,
  SCHEMA_VERSION,
  GridPositionSchema,
  BattlefieldSchema,
  GamePhaseSchema,
  ActionSchema,
  MatchParametersSchema,
  ClientMessageSchema,
  RANK_VALUES,
  PhalanxTurnResultSchema,
  TransactionLogEntrySchema,
} from '../src/schema';

describe('Shared schemas', () => {
  describe('SCHEMA_VERSION', () => {
    it('should be a valid semver string', () => {
      const semverPattern = /^\d+\.\d+\.\d+(?:[-+][A-Za-z0-9.-]+)?$/;
      expect(SCHEMA_VERSION).toMatch(semverPattern);
    });
  });

  describe('CardSchema', () => {
    it('should parse a valid card object', () => {
      const input = {
        id: 'test-id',
        suit: 'spades',
        face: 'A',
        value: 1,
        type: 'ace',
      };
      const result = CardSchema.safeParse(input);
      expect(result.success).toBe(true);
    });
  });

  describe('RANK_VALUES', () => {
    it('should map standard values correctly', () => {
      expect(RANK_VALUES.A).toBe(1);
      expect(RANK_VALUES['2']).toBe(2);
      expect(RANK_VALUES.T).toBe(10);
      expect(RANK_VALUES.J).toBe(11);
    });
  });

  describe('GridPositionSchema', () => {
    it('should accept valid positions', () => {
      expect(GridPositionSchema.safeParse({ row: 0, col: 0 }).success).toBe(true);
      expect(GridPositionSchema.safeParse({ row: 1, col: 3 }).success).toBe(true);
    });
  });

  describe('BattlefieldSchema', () => {
    it('should accept an 8-slot array', () => {
      const grid = Array(8).fill(null);
      expect(BattlefieldSchema.safeParse(grid).success).toBe(true);
    });
  });

  describe('GamePhaseSchema', () => {
    it('should accept all v1.0 phases', () => {
      const phases = [
        'StartTurn',
        'AttackPhase',
        'AttackResolution',
        'CleanupPhase',
        'ReinforcementPhase',
        'DrawPhase',
        'EndTurn',
        'gameOver',
      ];
      for (const p of phases) {
        expect(GamePhaseSchema.safeParse(p).success).toBe(true);
      }
    });
  });

  describe('ActionSchema', () => {
    it('should parse an attack action', () => {
      const action = {
        type: 'attack',
        playerIndex: 0,
        attackingColumn: 0,
        defendingColumn: 0,
        timestamp: '2026-01-01T00:00:00.000Z',
      };
      expect(ActionSchema.safeParse(action).success).toBe(true);
    });
  });

  describe('ClientMessageSchema createMatch matchParams', () => {
    it('should accept createMatch with no matchParams', () => {
      const result = ClientMessageSchema.safeParse({
        type: 'createMatch',
        playerName: 'Alice',
      });
      expect(result.success).toBe(true);
    });

    it('should accept createMatch with partial matchParams and preserve provided fields', () => {
      const result = ClientMessageSchema.safeParse({
        type: 'createMatch',
        playerName: 'Alice',
        matchParams: {
          rows: 3,
          columns: 5,
        },
      });
      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data).toMatchObject({
          type: 'createMatch',
          matchParams: {
            rows: 3,
            columns: 5,
          },
        });
      }
    });

    it('should reject out-of-range matchParams fields', () => {
      const invalidMessages = [
        { matchParams: { rows: 0 } },
        { matchParams: { columns: 13 } },
        { matchParams: { maxHandSize: -1 } },
        { matchParams: { initialDraw: 0 } },
      ];

      for (const payload of invalidMessages) {
        const result = ClientMessageSchema.safeParse({
          type: 'createMatch',
          playerName: 'Alice',
          ...payload,
        });
        expect(result.success).toBe(false);
      }
    });
  });

  describe('MatchParametersSchema — superRefine', () => {
    /** Valid baseline that passes all constraints */
    function validParams(overrides: Record<string, unknown> = {}) {
      return {
        specVersion: '1.0' as const,
        rows: 2,
        columns: 4,
        maxHandSize: 4,
        initialDraw: 12, // rows * columns + columns = 8 + 4
        modeClassicAces: true,
        modeClassicFaceCards: true,
        modeDamagePersistence: 'classic' as const,
        modeClassicDeployment: true,
        modeSpecialStart: { enabled: false },
        initiative: { deployFirst: 'P2' as const, attackFirst: 'P1' as const },
        modePassRules: { maxConsecutivePasses: 3, maxTotalPassesPerPlayer: 5 },
        classic: {
          enabled: true,
          mode: 'strict' as const,
          battlefield: { rows: 2, columns: 4 },
          hand: { maxHandSize: 4 },
          start: { initialDraw: 12 },
          modes: {
            classicAces: true,
            classicFaceCards: true,
            damagePersistence: 'classic' as const,
          },
          initiative: { deployFirst: 'P2' as const, attackFirst: 'P1' as const },
          passRules: { maxConsecutivePasses: 3, maxTotalPassesPerPlayer: 5 },
        },
        ...overrides,
      };
    }

    it('should accept valid classic strict parameters', () => {
      const result = MatchParametersSchema.safeParse(validParams());
      expect(result.success).toBe(true);
    });

    it('should reject totalSlots > 48', () => {
      // 12 rows * 4 columns = 48 slots, needs initialDraw = 52
      // But 13 * 4 = 52 > 48
      const result = MatchParametersSchema.safeParse(
        validParams({
          rows: 12,
          columns: 4,
          initialDraw: 52,
          classic: {
            enabled: false,
            mode: 'hybrid',
            battlefield: { rows: 12, columns: 4 },
            hand: { maxHandSize: 4 },
            start: { initialDraw: 52 },
            modes: { classicAces: true, classicFaceCards: true, damagePersistence: 'classic' },
            initiative: { deployFirst: 'P2', attackFirst: 'P1' },
            passRules: { maxConsecutivePasses: 3, maxTotalPassesPerPlayer: 5 },
          },
        }),
      );
      // 12 * 4 = 48, exactly at limit — should pass
      expect(result.success).toBe(true);

      // Now exceed: would need rows > 12 but max is 12, so use columns trick
      // Actually rows=12, columns=4 => 48 is exactly at limit. Not > 48.
      // We can't exceed with schema's max constraints (rows max 12, columns max 4).
    });

    it('should reject maxHandSize > columns', () => {
      const result = MatchParametersSchema.safeParse(
        validParams({
          maxHandSize: 5,
          columns: 4,
          classic: {
            enabled: false,
            mode: 'hybrid',
            battlefield: { rows: 2, columns: 4 },
            hand: { maxHandSize: 5 },
            start: { initialDraw: 12 },
            modes: { classicAces: true, classicFaceCards: true, damagePersistence: 'classic' },
            initiative: { deployFirst: 'P2', attackFirst: 'P1' },
            passRules: { maxConsecutivePasses: 3, maxTotalPassesPerPlayer: 5 },
          },
        }),
      );
      expect(result.success).toBe(false);
      if (!result.success) {
        const messages = result.error.issues.map((i) => i.message);
        expect(messages).toContain('Global Constraint: maxHandSize cannot exceed columns.');
      }
    });

    it('should reject initialDraw mismatch', () => {
      const result = MatchParametersSchema.safeParse(
        validParams({
          initialDraw: 10, // expected: 2*4 + 4 = 12
          classic: {
            enabled: false,
            mode: 'hybrid',
            battlefield: { rows: 2, columns: 4 },
            hand: { maxHandSize: 4 },
            start: { initialDraw: 10 },
            modes: { classicAces: true, classicFaceCards: true, damagePersistence: 'classic' },
            initiative: { deployFirst: 'P2', attackFirst: 'P1' },
            passRules: { maxConsecutivePasses: 3, maxTotalPassesPerPlayer: 5 },
          },
        }),
      );
      expect(result.success).toBe(false);
      if (!result.success) {
        const messages = result.error.issues.map((i) => i.message);
        expect(messages.some((m) => m.includes('Initial Draw Formula Mismatch'))).toBe(true);
      }
    });

    it('should reject strict mode parity violations', () => {
      const result = MatchParametersSchema.safeParse(
        validParams({
          rows: 2,
          classic: {
            enabled: true,
            mode: 'strict',
            battlefield: { rows: 1, columns: 4 }, // mismatch: rows 1 vs top-level 2
            hand: { maxHandSize: 4 },
            start: { initialDraw: 12 },
            modes: { classicAces: true, classicFaceCards: true, damagePersistence: 'classic' },
            initiative: { deployFirst: 'P2', attackFirst: 'P1' },
            passRules: { maxConsecutivePasses: 3, maxTotalPassesPerPlayer: 5 },
          },
        }),
      );
      expect(result.success).toBe(false);
      if (!result.success) {
        const messages = result.error.issues.map((i) => i.message);
        expect(messages.some((m) => m.includes('STRICT_MODE_VIOLATION'))).toBe(true);
      }
    });

    it('should skip strict parity checks when classic is disabled', () => {
      const result = MatchParametersSchema.safeParse(
        validParams({
          classic: {
            enabled: false,
            mode: 'strict',
            battlefield: { rows: 1, columns: 4 }, // mismatch but classic disabled
            hand: { maxHandSize: 4 },
            start: { initialDraw: 12 },
            modes: { classicAces: true, classicFaceCards: true, damagePersistence: 'classic' },
            initiative: { deployFirst: 'P2', attackFirst: 'P1' },
            passRules: { maxConsecutivePasses: 3, maxTotalPassesPerPlayer: 5 },
          },
        }),
      );
      expect(result.success).toBe(true);
    });
  });
});

describe('TransactionLogEntrySchema', () => {
  it('preserves turnHash in parsed output when field is present', () => {
    const result = TransactionLogEntrySchema.partial().safeParse({
      turnHash: 'a'.repeat(64),
    });
    expect(result.success).toBe(true);
    expect((result.data as { turnHash?: string }).turnHash).toBe('a'.repeat(64));
  });

  it('accepts a valid entry without turnHash (field is optional)', () => {
    const result = TransactionLogEntrySchema.partial().safeParse({});
    expect(result.success).toBe(true);
    expect((result.data as { turnHash?: string }).turnHash).toBeUndefined();
  });

  it('rejects a non-string turnHash', () => {
    const result = TransactionLogEntrySchema.partial().safeParse({
      turnHash: 12345,
    });
    expect(result.success).toBe(false);
  });
});

describe('PhalanxTurnResultSchema', () => {
